// Cap for strnlen() over arbitrary C strings inside this test suite. Picked
// far above any realistic test input so behavior is unchanged, but bounded
// so static analyzers don't flag the read as unbounded (cpp:S5813).
static constexpr std::size_t TEST_STR_MAX = 4u * 1024u * 1024u;  // 4 MiB

// Cross-platform temp directory path.
static const std::string g_tmp_dir = std::filesystem::temp_directory_path().string();

// Build a cross-platform temp file path. Uses a ring of buffers so multiple
// calls can be live simultaneously (e.g. file1/file2 in the same scope).
static const char* tmp_path(const char* name) {
    static char bufs[8][1024];
    static int idx = 0;
    char* buf = bufs[idx++ & 7];
    snprintf(buf, 1024, "%s/%s", g_tmp_dir.c_str(), name);
    return buf;
}

// ===================================================================
//  Minimal PXR-free USDA text emitter (mirrors UsdaTextWriter output
//  format, but uses only raw C++ types + nanousd C API)
// ===================================================================

class MiniUsdaWriter
{
public:
    explicit MiniUsdaWriter(std::ostream& os, const std::string& defaultPrim = "")
        : _os(os), _depth(0)
    {
        _os << "#usda 1.0\n";
        if (!defaultPrim.empty())
        {
            _os << "(\n    defaultPrim = \"" << defaultPrim << "\"\n)\n";
        }
    }

    void beginPrim(const std::string& typeName, const std::string& path)
    {
        std::string leafName = path;
        auto pos = path.rfind('/');
        if (pos != std::string::npos) leafName = path.substr(pos + 1);
        _os << "\n";
        _indent();
        _os << "def " << typeName << " \"" << leafName << "\"\n";
        _indent();
        _os << "{\n";
        _depth++;
    }

    void endPrim()
    {
        if (_depth > 0) _depth--;
        _indent();
        _os << "}\n";
    }

    // -- Scalar writers --

    void writeInt(const std::string& name, int v)
    {
        _indent(); _os << "int " << name << " = " << v << "\n";
    }
    void writeFloat(const std::string& name, float v)
    {
        _indent(); _os << "float " << name << " = " << _fmtF(v) << "\n";
    }
    void writeDouble(const std::string& name, double v)
    {
        _indent(); _os << "double " << name << " = " << _fmtD(v) << "\n";
    }
    void writeBool(const std::string& name, bool v)
    {
        _indent(); _os << "bool " << name << " = " << (v ? "true" : "false") << "\n";
    }
    void writeToken(const std::string& name, const std::string& v)
    {
        _indent(); _os << "token " << name << " = \"" << v << "\"\n";
    }
    void writeAsset(const std::string& name, const std::string& v)
    {
        _indent(); _os << "asset " << name << " = @" << v << "@\n";
    }
    void writeVec2i(const std::string& name, const int v[2])
    {
        _indent(); _os << "int2 " << name << " = ("
                       << v[0] << ", " << v[1] << ")\n";
    }
    void writeVec2f(const std::string& name, const float v[2])
    {
        _indent(); _os << "float2 " << name << " = ("
                       << _fmtF(v[0]) << ", " << _fmtF(v[1]) << ")\n";
    }
    void writeColor3f(const std::string& name, const float v[3])
    {
        _indent(); _os << "color3f " << name << " = ("
                       << _fmtF(v[0]) << ", " << _fmtF(v[1]) << ", " << _fmtF(v[2]) << ")\n";
    }
    void writeVec3f(const std::string& name, const float v[3])
    {
        _indent(); _os << "float3 " << name << " = ("
                       << _fmtF(v[0]) << ", " << _fmtF(v[1]) << ", " << _fmtF(v[2]) << ")\n";
    }
    void writeTypedVec3f(const char* typeName, const std::string& name, const float v[3])
    {
        _indent(); _os << typeName << " " << name << " = ("
                       << _fmtF(v[0]) << ", " << _fmtF(v[1]) << ", " << _fmtF(v[2]) << ")\n";
    }
    void writeVec4f(const std::string& name, const float v[4])
    {
        _indent(); _os << "float4 " << name << " = ("
                       << _fmtF(v[0]) << ", " << _fmtF(v[1]) << ", "
                       << _fmtF(v[2]) << ", " << _fmtF(v[3]) << ")\n";
    }
    void writeVec3d(const std::string& name, const double v[3])
    {
        _indent(); _os << "double3 " << name << " = ("
                       << _fmtD(v[0]) << ", " << _fmtD(v[1]) << ", " << _fmtD(v[2]) << ")\n";
    }
    void writeTypedVec3d(const char* typeName, const std::string& name, const double v[3])
    {
        _indent(); _os << typeName << " " << name << " = ("
                       << _fmtD(v[0]) << ", " << _fmtD(v[1]) << ", " << _fmtD(v[2]) << ")\n";
    }
    void writeQuatf(const std::string& name, const float v[4])
    {
        _indent(); _os << "quatf " << name << " = ("
                       << _fmtF(v[0]) << ", " << _fmtF(v[1]) << ", "
                       << _fmtF(v[2]) << ", " << _fmtF(v[3]) << ")\n";
    }
    void writeFloat4Array(const std::string& name, const float* d, size_t count)
    {
        _indent(); _os << "float4[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 4;
            _os << "(" << _fmtF(d[b]) << ", " << _fmtF(d[b+1]) << ", "
                << _fmtF(d[b+2]) << ", " << _fmtF(d[b+3]) << ")";
        }
        _os << "]\n";
    }
    void writeAssetArray(const std::string& name, const std::vector<std::string>& v)
    {
        _indent(); _os << "asset[] " << name << " = [";
        for (size_t i = 0; i < v.size(); i++)
        { if (i) _os << ", "; _os << "@" << v[i] << "@"; }
        _os << "]\n";
    }
    void writeMatrix4d(const std::string& name, const double m[16])
    {
        _indent(); _os << "matrix4d " << name << " = ( ";
        for (int r = 0; r < 4; r++)
        {
            if (r > 0) _os << ", ";
            int b = r * 4;
            _os << "(" << _fmtD(m[b]) << ", " << _fmtD(m[b+1]) << ", "
                << _fmtD(m[b+2]) << ", " << _fmtD(m[b+3]) << ")";
        }
        _os << " )\n";
    }

    // -- Array writers --

    void writeIntArray(const std::string& name, const int* d, size_t n)
    {
        _indent(); _os << "int[] " << name << " = [";
        for (size_t i = 0; i < n; i++) { if (i) _os << ", "; _os << d[i]; }
        _os << "]\n";
    }
    void writeFloatArray(const std::string& name, const float* d, size_t n)
    {
        _indent(); _os << "float[] " << name << " = [";
        for (size_t i = 0; i < n; i++) { if (i) _os << ", "; _os << _fmtF(d[i]); }
        _os << "]\n";
    }
    void writeVec3fArray(const std::string& name, const char* typeName,
                         const float* d, size_t count)
    {
        _indent(); _os << typeName << "[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 3;
            _os << "(" << _fmtF(d[b]) << ", " << _fmtF(d[b+1]) << ", " << _fmtF(d[b+2]) << ")";
        }
        _os << "]\n";
    }
    void writeVec2fArray(const std::string& name, const float* d, size_t count)
    {
        _indent(); _os << "float2[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 2;
            _os << "(" << _fmtF(d[b]) << ", " << _fmtF(d[b+1]) << ")";
        }
        _os << "]\n";
    }
    void writeVec3dArray(const std::string& name, const char* typeName,
                         const double* d, size_t count)
    {
        _indent(); _os << typeName << "[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 3;
            _os << "(" << _fmtD(d[b]) << ", " << _fmtD(d[b+1]) << ", " << _fmtD(d[b+2]) << ")";
        }
        _os << "]\n";
    }
    void writeMatrix4dArray(const std::string& name, const double* d, size_t count)
    {
        _indent(); _os << "matrix4d[] " << name << " = [\n";
        for (size_t i = 0; i < count; i++)
        {
            size_t b = i * 16;
            _indent(); _os << "    ";
            if (i > 0) _os << ", ";
            else       _os << "  ";
            _os << "( ";
            for (int r = 0; r < 4; r++)
            {
                if (r > 0) _os << ", ";
                int rb = b + r * 4;
                _os << "(" << _fmtD(d[rb]) << ", " << _fmtD(d[rb+1]) << ", "
                    << _fmtD(d[rb+2]) << ", " << _fmtD(d[rb+3]) << ")";
            }
            _os << " )\n";
        }
        _indent(); _os << "]\n";
    }
    void writeQuatfArray(const std::string& name, const float* d, size_t count)
    {
        _indent(); _os << "quatf[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 4;
            _os << "(" << _fmtF(d[b]) << ", " << _fmtF(d[b+1]) << ", "
                << _fmtF(d[b+2]) << ", " << _fmtF(d[b+3]) << ")";
        }
        _os << "]\n";
    }
    void writeHalf3Array(const std::string& name, const float* d, size_t count)
    {
        _indent(); _os << "half3[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 3;
            _os << "(" << _fmtF(d[b]) << ", " << _fmtF(d[b+1]) << ", " << _fmtF(d[b+2]) << ")";
        }
        _os << "]\n";
    }
    void writeQuathArray(const std::string& name, const float* d, size_t count)
    {
        _indent(); _os << "quath[] " << name << " = [";
        for (size_t i = 0; i < count; i++)
        {
            if (i) _os << ", ";
            size_t b = i * 4;
            _os << "(" << _fmtF(d[b]) << ", " << _fmtF(d[b+1]) << ", "
                << _fmtF(d[b+2]) << ", " << _fmtF(d[b+3]) << ")";
        }
        _os << "]\n";
    }
    void writeInt64Array(const std::string& name, const int64_t* d, size_t n)
    {
        _indent(); _os << "int64[] " << name << " = [";
        for (size_t i = 0; i < n; i++) { if (i) _os << ", "; _os << d[i]; }
        _os << "]\n";
    }
    void writeTokenArray(const std::string& name, const std::vector<std::string>& v)
    {
        _indent(); _os << "uniform token[] " << name << " = [";
        for (size_t i = 0; i < v.size(); i++)
        { if (i) _os << ", "; _os << "\"" << v[i] << "\""; }
        _os << "]\n";
    }
    void writeStringArray(const std::string& name, const std::vector<std::string>& v)
    {
        _indent(); _os << "string[] " << name << " = [";
        for (size_t i = 0; i < v.size(); i++)
        { if (i) _os << ", "; _os << "\"" << v[i] << "\""; }
        _os << "]\n";
    }

    // -- Relationships & connections --

    void writeRel(const std::string& name, const std::string& target)
    {
        _indent(); _os << "rel " << name << " = <" << target << ">\n";
    }
    void writeConnection(const std::string& attrType, const std::string& attrName,
                         const std::string& source)
    {
        _indent(); _os << attrType << " " << attrName << ".connect = <" << source << ">\n";
    }

private:
    std::ostream& _os;
    int _depth;
    void _indent() { for (int i = 0; i < _depth; i++) _os << "    "; }
    static std::string _fmtF(float v)
    {
        char buf[32];
        int n = snprintf(buf, sizeof(buf), "%g", v);
        return std::string(buf, n);
    }
    static std::string _fmtD(double v)
    { std::ostringstream s; s << std::setprecision(17) << v; return s.str(); }
};

// ===================================================================
//  Minimal test framework (no external dependency)
// ===================================================================

static int g_passes = 0;
static int g_failures = 0;

#define TEST_ASSERT(cond) do { \
    if (!(cond)) { \
        fprintf(stderr, "FAIL: %s:%d: %s\n", __FILE__, __LINE__, #cond); \
        g_failures++; \
    } else { \
        g_passes++; \
    } \
} while (0)

#define TEST_ASSERT_MSG(cond, msg) do { \
    if (!(cond)) { \
        fprintf(stderr, "FAIL: %s:%d: %s -- %s\n", __FILE__, __LINE__, #cond, (msg)); \
        g_failures++; \
    } else { \
        g_passes++; \
    } \
} while (0)

#define TEST_STR_HAS(haystack, needle) do { \
    if ((haystack).find(needle) == std::string::npos) { \
        fprintf(stderr, "FAIL: %s:%d: output missing \"%s\"\n", \
                __FILE__, __LINE__, (needle)); \
        g_failures++; \
    } else { \
        g_passes++; \
    } \
} while (0)

#define TEST_STR_LACKS(haystack, needle) do { \
    if ((haystack).find(needle) != std::string::npos) { \
        fprintf(stderr, "FAIL: %s:%d: output unexpectedly contains \"%s\"\n", \
                __FILE__, __LINE__, (needle)); \
        g_failures++; \
    } else { \
        g_passes++; \
    } \
} while (0)

#define SECTION(name) printf("\n--- %s ---\n", (name))

// ===================================================================
//  Helpers
// ===================================================================

static std::string safeStr(const char* s)
{
    return s ? std::string(s) : std::string();
}

static void findPrimsByType(NanousdPrim prim, const char* typeName,
                            std::vector<NanousdPrim>& out)
{
    if (!prim) return;
    std::string t = safeStr(nanousd_typename(prim));
    if (t == typeName) out.push_back(prim);
    int n = nanousd_nchildren(prim);
    for (int i = 0; i < n; i++)
        findPrimsByType(nanousd_child(prim, i), typeName, out);
}

// Infer the USDA vec3f type name from an attribute name.
static const char* inferVec3fType(const std::string& name)
{
    if (name.find("points") != std::string::npos ||
        name.find("positions") != std::string::npos)
        return "point3f";
    if (name.find("normals") != std::string::npos)
        return "normal3f";
    if (name.find("color") != std::string::npos ||
        name.find("displayColor") != std::string::npos)
        return "color3f";
    if (name.find("extent") != std::string::npos)
        return "float3";
    return "float3";
}

static const char* inferVec3dType(const std::string& name)
{
    if (name.find("points") != std::string::npos) return "point3d";
    if (name.find("normals") != std::string::npos) return "normal3d";
    return "double3";
}

// ===================================================================
//  Serialize a prim subtree via nanousd reads -> MiniUsdaWriter
// ===================================================================

static void serializePrim(NanousdPrim prim, MiniUsdaWriter& w)
{
    std::string path = safeStr(nanousd_path(prim));
    std::string type = safeStr(nanousd_typename(prim));
    w.beginPrim(type, path);

    int nA = nanousd_nattribs(prim);
    for (int a = 0; a < nA; a++)
    {
        std::string name = safeStr(nanousd_attribname(prim, a));
        std::string atype = safeStr(nanousd_attribtype(prim, name.c_str()));
        int alen = nanousd_attribarraylen(prim, name.c_str());

        // Array attributes
        if (alen > 0)
        {
            if (atype == "point3f[]" || atype == "normal3f[]" ||
                atype == "vector3f[]" || atype == "color3f[]" ||
                atype == "float3[]")
            {
                std::vector<float> buf(alen * 3);
                int got = nanousd_attribarrayv3f(prim, name.c_str(), buf.data(), alen);
                if (got > 0)
                    w.writeVec3fArray(name, inferVec3fType(name), buf.data(), (size_t)got);
            }
            else if (atype == "texCoord2f[]" || atype == "float2[]")
            {
                std::vector<float> buf(alen * 2);
                int got = nanousd_attribarrayf(prim, name.c_str(), buf.data(), alen * 2);
                if (got > 0) w.writeVec2fArray(name, buf.data(), (size_t)(got / 2));
            }
            else if (atype == "int2" && alen == 2)
            {
                int v[2];
                nanousd_attribarrayi(prim, name.c_str(), v, 2);
                w.writeVec2i(name, v);
            }
            else if (atype == "int[]")
            {
                std::vector<int> buf(alen);
                nanousd_attribarrayi(prim, name.c_str(), buf.data(), alen);
                w.writeIntArray(name, buf.data(), (size_t)alen);
            }
            else if (atype == "float[]")
            {
                std::vector<float> buf(alen);
                nanousd_attribarrayf(prim, name.c_str(), buf.data(), alen);
                w.writeFloatArray(name, buf.data(), (size_t)alen);
            }
            else if (atype == "double3[]" || atype == "point3d[]" ||
                     atype == "normal3d[]" || atype == "vector3d[]")
            {
                std::vector<double> buf(alen * 3);
                int got = nanousd_attribarrayv3d(prim, name.c_str(), buf.data(), alen);
                if (got > 0)
                    w.writeVec3dArray(name, inferVec3dType(name), buf.data(), (size_t)got);
            }
            else if (atype == "matrix4d[]")
            {
                std::vector<double> buf(alen * 16);
                int got = nanousd_attribarrayd(prim, name.c_str(), buf.data(), alen * 16);
                if (got > 0) w.writeMatrix4dArray(name, buf.data(), (size_t)(got / 16));
            }
            else if (atype == "quatf[]")
            {
                std::vector<float> buf(alen * 4);
                int got = nanousd_attribarrayf(prim, name.c_str(), buf.data(), alen * 4);
                if (got > 0) w.writeQuatfArray(name, buf.data(), (size_t)(got / 4));
            }
            else if (atype == "half3[]")
            {
                // half3 read as float3 via nanousd
                std::vector<float> buf(alen * 3);
                int got = nanousd_attribarrayf(prim, name.c_str(), buf.data(), alen * 3);
                if (got > 0) w.writeHalf3Array(name, buf.data(), (size_t)(got / 3));
            }
            else if (atype == "quath[]")
            {
                // quath read as float via nanousd (half -> float)
                std::vector<float> buf(alen * 4);
                int got = nanousd_attribarrayf(prim, name.c_str(), buf.data(), alen * 4);
                if (got > 0) w.writeQuathArray(name, buf.data(), (size_t)(got / 4));
            }
            else if (atype == "int64[]")
            {
                std::vector<int64_t> buf(alen);
                int got = nanousd_attribarrayi64(prim, name.c_str(), buf.data(), alen);
                if (got > 0) w.writeInt64Array(name, buf.data(), (size_t)got);
            }
            else if (atype == "float4[]")
            {
                std::vector<float> buf(alen * 4);
                int got = nanousd_attribarrayf(prim, name.c_str(), buf.data(), alen * 4);
                if (got > 0) w.writeFloat4Array(name, buf.data(), (size_t)(got / 4));
            }
            else if (atype == "asset[]")
            {
                std::vector<std::string> elems;
                for (int e = 0; e < alen; e++)
                    elems.push_back(safeStr(nanousd_attribarrays_elem(prim, name.c_str(), e)));
                w.writeAssetArray(name, elems);
            }
            else if (atype == "token[]" || atype == "string[]")
            {
                std::vector<std::string> elems;
                for (int e = 0; e < alen; e++)
                    elems.push_back(safeStr(nanousd_attribarrays_elem(prim, name.c_str(), e)));
                if (atype == "token[]") w.writeTokenArray(name, elems);
                else                    w.writeStringArray(name, elems);
            }
            continue;
        }

        // Scalar attributes
        int ok = 0;
        if (atype == "float")
        {
            float v = nanousd_attribf(prim, name.c_str(), &ok);
            if (ok) w.writeFloat(name, v);
        }
        else if (atype == "double")
        {
            double v = nanousd_attribd(prim, name.c_str(), &ok);
            if (ok) w.writeDouble(name, v);
        }
        else if (atype == "int")
        {
            int v = nanousd_attribi(prim, name.c_str(), &ok);
            if (ok) w.writeInt(name, v);
        }
        else if (atype == "bool")
        {
            int v = nanousd_attribb(prim, name.c_str(), &ok);
            if (ok) w.writeBool(name, (bool)v);
        }
        else if (atype == "token" || atype == "string")
        {
            const char* v = nanousd_attribs(prim, name.c_str(), &ok);
            if (ok && v) { std::string s(v); w.writeToken(name, s); }
        }
        else if (atype == "asset")
        {
            const char* v = nanousd_attribs(prim, name.c_str(), &ok);
            if (ok && v) w.writeAsset(name, std::string(v));
        }
        else if (atype == "float2")
        {
            float v[2];
            if (nanousd_attribv2f(prim, name.c_str(), v)) w.writeVec2f(name, v);
        }
        else if (atype == "color3f")
        {
            float v[3];
            if (nanousd_attribv3f(prim, name.c_str(), v)) w.writeColor3f(name, v);
        }
        else if (atype == "normal3f")
        {
            float v[3];
            if (nanousd_attribv3f(prim, name.c_str(), v)) w.writeTypedVec3f("normal3f", name, v);
        }
        else if (atype == "float3")
        {
            float v[3];
            if (nanousd_attribv3f(prim, name.c_str(), v)) w.writeVec3f(name, v);
        }
        else if (atype == "float4")
        {
            float v[4];
            if (nanousd_attribv4f(prim, name.c_str(), v)) w.writeVec4f(name, v);
        }
        else if (atype == "point3f")
        {
            float v[3];
            if (nanousd_attribv3f(prim, name.c_str(), v)) w.writeTypedVec3f("point3f", name, v);
        }
        else if (atype == "vector3f")
        {
            float v[3];
            if (nanousd_attribv3f(prim, name.c_str(), v)) w.writeTypedVec3f("vector3f", name, v);
        }
        else if (atype == "vector3d")
        {
            double v[3];
            if (nanousd_attribv3d(prim, name.c_str(), v)) w.writeTypedVec3d("vector3d", name, v);
        }
        else if (atype == "quatf")
        {
            float v[4];
            if (nanousd_attribqf(prim, name.c_str(), v)) w.writeQuatf(name, v);
        }
        else if (atype == "double3")
        {
            double v[3];
            if (nanousd_attribv3d(prim, name.c_str(), v)) w.writeVec3d(name, v);
        }
        else if (atype == "matrix4d")
        {
            double m[16];
            if (nanousd_attribm4d(prim, name.c_str(), m)) w.writeMatrix4d(name, m);
        }
    }

    // Relationships
    static const char* knownRels[] = {
        "material:binding", "skel:skeleton", "skel:animationSource",
        "proxyPrim", "prototypes", nullptr
    };
    for (int ri = 0; knownRels[ri]; ri++)
    {
        if (nanousd_hasrel(prim, knownRels[ri]))
        {
            const char* t = nanousd_reltarget(prim, knownRels[ri], 0);
            if (t) { std::string ts(t); w.writeRel(knownRels[ri], ts); }
        }
    }

    // Attribute connections (shader graphs)
    for (int a = 0; a < nA; a++)
    {
        std::string name = safeStr(nanousd_attribname(prim, a));
        if (nanousd_hasconnections(prim, name.c_str()))
        {
            std::string atype = safeStr(nanousd_attribtype(prim, name.c_str()));
            // Strip trailing [] for array types
            if (atype.size() > 2 && atype.substr(atype.size()-2) == "[]")
                atype = atype.substr(0, atype.size()-2);
            int nc = nanousd_nconnections(prim, name.c_str());
            for (int c = 0; c < nc; c++)
            {
                std::string ct = safeStr(nanousd_connection(prim, name.c_str(), c));
                if (!ct.empty()) w.writeConnection(atype, name, ct);
            }
        }
    }

    // Recurse into children
    int nch = nanousd_nchildren(prim);
    for (int i = 0; i < nch; i++)
        serializePrim(nanousd_child(prim, i), w);

    w.endPrim();
}

static std::string serializeStage(NanousdStage stage)
{
    std::ostringstream oss;

    // Extract default prim name for stage metadata
    NanousdPrim root = nanousd_defaultprim(stage);
    std::string defaultPrimName;
    if (root)
    {
        std::string rpath = safeStr(nanousd_path(root));
        auto pos = rpath.rfind('/');
        defaultPrimName = (pos != std::string::npos) ? rpath.substr(pos + 1) : rpath;
    }

    MiniUsdaWriter w(oss, defaultPrimName);

    if (root)
    {
        serializePrim(root, w);
    }
    else
    {
        int n = nanousd_nprims(stage);
        for (int i = 0; i < n; i++)
        {
            NanousdPrim p = nanousd_prim(stage, i);
            std::string path = safeStr(nanousd_path(p));
            if (path == "/" || path.empty()) continue;
            if ((int)std::count(path.begin(), path.end(), '/') == 1)
                serializePrim(p, w);
        }
    }
    return oss.str();
}

// ===================================================================
//  TEST 1: Mesh roundtrip — topology, points, normals, UVs
// ===================================================================

static void test_mesh_roundtrip(const char* dataDir)
{
    SECTION("test_mesh_roundtrip");

    std::string filepath = std::string(dataDir) + "/simple_mesh.usda";
    NanousdStage stage = nanousd_open(filepath.c_str());
    TEST_ASSERT_MSG(stage != nullptr, "open simple_mesh.usda");
    if (!stage) return;

    std::string out = serializeStage(stage);
    printf("  Serialized %zu bytes\n", out.size());

    TEST_STR_HAS(out, "#usda 1.0");
    TEST_STR_HAS(out, "def Xform \"World\"");
    TEST_STR_HAS(out, "def Mesh \"SimpleMesh\"");

    // Topology arrays
    TEST_STR_HAS(out, "int[] faceVertexCounts");
    TEST_STR_HAS(out, "int[] faceVertexIndices");

    // Points
    TEST_STR_HAS(out, "point3f[] points");
    TEST_STR_HAS(out, "-1");  // first point x

    // Normals
    TEST_STR_HAS(out, "normal3f[] normals");
    TEST_STR_HAS(out, "0.7071");  // known normal component

    // UVs
    TEST_STR_HAS(out, "primvars:st");

    // Transforms
    TEST_STR_HAS(out, "xformOp:translate");
    TEST_STR_HAS(out, "xformOp:rotateXYZ");
    TEST_STR_HAS(out, "xformOp:scale");
    TEST_STR_HAS(out, "xformOpOrder");

    // Subdivision scheme
    TEST_STR_HAS(out, "subdivisionScheme");
    TEST_STR_HAS(out, "none");

    // Material binding
    TEST_STR_HAS(out, "material:binding");
    TEST_STR_HAS(out, "/World/Materials/SimpleMat");

    // Material sub-tree
    TEST_STR_HAS(out, "def Material \"SimpleMat\"");
    TEST_STR_HAS(out, "def Shader \"Shader\"");

    nanousd_close(stage);
}

