// ===================================================================
//  TEST 6: Transform hierarchy — nested xforms, matrix values
// ===================================================================

static void test_transform_hierarchy(const char* dataDir)
{
    SECTION("test_transform_hierarchy");

    std::string filepath = std::string(dataDir) + "/transform_hierarchy.usda";
    NanousdStage stage = nanousd_open(filepath.c_str());
    TEST_ASSERT_MSG(stage != nullptr, "open transform_hierarchy.usda");
    if (!stage) return;

    std::string out = serializeStage(stage);
    printf("  Serialized %zu bytes\n", out.size());

    TEST_STR_HAS(out, "def Xform \"Root\"");
    TEST_STR_HAS(out, "def Xform \"Child_A\"");
    TEST_STR_HAS(out, "def Xform \"GrandChild\"");
    TEST_STR_HAS(out, "def Mesh \"Leaf\"");
    TEST_STR_HAS(out, "def Xform \"Child_B\"");

    // Transform types
    TEST_STR_HAS(out, "xformOp:translate");
    TEST_STR_HAS(out, "xformOp:rotateXYZ");
    TEST_STR_HAS(out, "xformOp:scale");
    TEST_STR_HAS(out, "xformOpOrder");
    TEST_STR_HAS(out, "xformOp:transform");
    TEST_STR_HAS(out, "matrix4d");

    // Matrix row with translations
    TEST_STR_HAS(out, "100");
    TEST_STR_HAS(out, "200");
    TEST_STR_HAS(out, "300");

    // Verify hierarchy ordering
    size_t rootP   = out.find("def Xform \"Root\"");
    size_t childAP = out.find("def Xform \"Child_A\"");
    size_t gcP     = out.find("def Xform \"GrandChild\"");
    size_t leafP   = out.find("def Mesh \"Leaf\"");
    size_t childBP = out.find("def Xform \"Child_B\"");
    TEST_ASSERT(rootP   != std::string::npos);
    TEST_ASSERT(childAP != std::string::npos);
    TEST_ASSERT(gcP     != std::string::npos);
    TEST_ASSERT(leafP   != std::string::npos);
    TEST_ASSERT(childBP != std::string::npos);
    TEST_ASSERT(rootP < childAP);
    TEST_ASSERT(childAP < gcP);
    TEST_ASSERT(gcP < leafP);
    TEST_ASSERT(leafP < childBP);

    // Leaf mesh topology
    TEST_STR_HAS(out, "faceVertexCounts");
    TEST_STR_HAS(out, "faceVertexIndices");

    nanousd_close(stage);
}

