// ===================================================================
//  TEST 8: Full scene — serialize everything, comprehensive check
// ===================================================================

static void test_full_scene(const char* dataDir)
{
    SECTION("test_full_scene");

    std::string filepath = std::string(dataDir) + "/full_scene.usda";
    NanousdStage stage = nanousd_open(filepath.c_str());
    TEST_ASSERT_MSG(stage != nullptr, "open full_scene.usda");
    if (!stage) return;

    std::string out = serializeStage(stage);
    printf("  Full scene: %zu bytes\n", out.size());

    // Structure
    TEST_STR_HAS(out, "#usda 1.0");
    TEST_STR_HAS(out, "def Xform \"World\"");

    // Cameras
    TEST_STR_HAS(out, "def Camera \"MainCamera\"");
    TEST_STR_HAS(out, "def Camera \"TopDownCamera\"");
    TEST_STR_HAS(out, "focalLength");
    TEST_STR_HAS(out, "horizontalAperture");
    TEST_STR_HAS(out, "clippingRange");
    TEST_STR_HAS(out, "perspective");

    // Lights
    TEST_STR_HAS(out, "def Xform \"Lights\"");
    TEST_STR_HAS(out, "def DomeLight \"Sky\"");
    TEST_STR_HAS(out, "def DistantLight \"Sun\"");
    TEST_STR_HAS(out, "def RectLight \"FillLight\"");
    TEST_STR_HAS(out, "def SphereLight \"AccentLight\"");
    TEST_STR_HAS(out, "inputs:intensity");
    TEST_STR_HAS(out, "inputs:color");
    TEST_STR_HAS(out, "inputs:angle");
    TEST_STR_HAS(out, "inputs:radius");

    // Ground
    TEST_STR_HAS(out, "def Mesh \"Ground\"");

    // Geometry
    TEST_STR_HAS(out, "def Xform \"Geometry\"");
    TEST_STR_HAS(out, "def Mesh \"Table\"");
    TEST_STR_HAS(out, "def Mesh \"Vase\"");
    TEST_STR_HAS(out, "def Mesh \"MultiMatCube\"");
    TEST_STR_HAS(out, "def Mesh \"HiddenCube\"");

    // Curves
    TEST_STR_HAS(out, "def Xform \"Curves\"");
    TEST_STR_HAS(out, "def BasisCurves \"Wire\"");
    TEST_STR_HAS(out, "def BasisCurves \"Rope\"");
    TEST_STR_HAS(out, "curveVertexCounts");
    TEST_STR_HAS(out, "widths");

    // Points
    TEST_STR_HAS(out, "def Points \"Sparks\"");

    // Instancer
    TEST_STR_HAS(out, "def PointInstancer \"Pillars\"");

    // Skeleton
    TEST_STR_HAS(out, "def SkelRoot \"Figurine\"");

    // Mesh completeness
    TEST_STR_HAS(out, "int[] faceVertexCounts");
    TEST_STR_HAS(out, "int[] faceVertexIndices");
    TEST_STR_HAS(out, "point3f[] points");
    TEST_STR_HAS(out, "normal3f[] normals");
    TEST_STR_HAS(out, "primvars:st");
    TEST_STR_HAS(out, "subdivisionScheme");

    // Material bindings
    TEST_STR_HAS(out, "material:binding");
    TEST_STR_HAS(out, "/World/Materials/WoodMat");
    TEST_STR_HAS(out, "/World/Materials/CeramicMat");
    TEST_STR_HAS(out, "/World/Materials/GroundMat");
    TEST_STR_HAS(out, "/World/Materials/MetalMat");

    // Materials
    TEST_STR_HAS(out, "def Scope \"Materials\"");
    TEST_STR_HAS(out, "def Material \"GroundMat\"");
    TEST_STR_HAS(out, "def Material \"WoodMat\"");
    TEST_STR_HAS(out, "def Material \"CeramicMat\"");
    TEST_STR_HAS(out, "def Material \"MetalMat\"");
    TEST_STR_HAS(out, "def Shader \"Surface\"");
    TEST_STR_HAS(out, "UsdPreviewSurface");
    TEST_STR_HAS(out, "inputs:diffuseColor");
    TEST_STR_HAS(out, "inputs:roughness");
    TEST_STR_HAS(out, "inputs:metallic");
    TEST_STR_HAS(out, "outputs:surface");

    // Transforms
    TEST_STR_HAS(out, "xformOp:translate");
    TEST_STR_HAS(out, "xformOp:rotateXYZ");
    TEST_STR_HAS(out, "xformOpOrder");

    // No PXR artifacts
    TEST_STR_LACKS(out, "PXR_NS");
    TEST_STR_LACKS(out, "pxr::");
    TEST_STR_LACKS(out, "VtValue");

    // Ordering: alphabetical by prim name — Geometry < Lights < MainCamera < Materials
    size_t camP   = out.find("def Camera \"MainCamera\"");
    size_t lightP = out.find("def Xform \"Lights\"");
    size_t geomP  = out.find("def Xform \"Geometry\"");
    size_t matP   = out.find("def Scope \"Materials\"");
    TEST_ASSERT(camP   != std::string::npos);
    TEST_ASSERT(lightP != std::string::npos);
    TEST_ASSERT(geomP  != std::string::npos);
    TEST_ASSERT(matP   != std::string::npos);
    TEST_ASSERT(geomP < lightP);
    TEST_ASSERT(lightP < camP);
    TEST_ASSERT(camP < matP);

    // Balanced braces
    int braces = 0;
    for (char c : out) { if (c == '{') braces++; if (c == '}') braces--; }
    TEST_ASSERT_MSG(braces == 0, "balanced braces");

    // Prim count (at least 14 defs)
    size_t defCount = 0;
    size_t pos = 0;
    while ((pos = out.find("def ", pos)) != std::string::npos) { defCount++; pos += 4; }
    printf("  %zu prim definitions\n", defCount);
    TEST_ASSERT_MSG(defCount >= 14, "at least 14 prim defs");

    nanousd_close(stage);
}

