// ===================================================================
//  TEST 16: Re-read verification — write then re-parse via nanousd
// ===================================================================

static void test_reread_verification(const char* dataDir)
{
    SECTION("test_reread_verification");

    std::string filepath = std::string(dataDir) + "/simple_mesh.usda";
    NanousdStage stage = nanousd_open(filepath.c_str());
    TEST_ASSERT_MSG(stage != nullptr, "open simple_mesh.usda for re-read");
    if (!stage) return;

    NanousdPrim root = nanousd_defaultprim(stage);
    TEST_ASSERT(root != nullptr);

    // Record original mesh data
    std::vector<NanousdPrim> origMeshes;
    findPrimsByType(root, "Mesh", origMeshes);
    int origMeshCount = (int)origMeshes.size();
    printf("  Original: %d mesh(es)\n", origMeshCount);

    std::vector<int> origPtCounts, origFcCounts;
    std::vector<std::vector<float>> origPtData;
    for (auto& m : origMeshes)
    {
        int np = nanousd_attribarraylen(m, "points");
        int nf = nanousd_attribarraylen(m, "faceVertexCounts");
        origPtCounts.push_back(np);
        origFcCounts.push_back(nf);
        std::vector<float> pts(np * 3);
        nanousd_attribarrayv3f(m, "points", pts.data(), np);
        origPtData.push_back(std::move(pts));
    }

    // Serialize
    std::string serialized = serializeStage(stage);
    TEST_ASSERT(serialized.size() > 100);
    printf("  Serialized: %zu bytes\n", serialized.size());

    // Write temp file
    const char* tmpFile = tmp_path("test_usda_serialization_reread.usda");
    FILE* f = fopen(tmpFile, "w");
    TEST_ASSERT_MSG(f != nullptr, "create temp file");
    if (!f) { nanousd_close(stage); return; }
    fwrite(serialized.c_str(), 1, serialized.size(), f);
    fclose(f);

    // Re-read via nanousd
    NanousdStage reStage = nanousd_open(tmpFile);
    if (reStage)
    {
        int rePrimCount = nanousd_nprims(reStage);
        printf("  Re-read: %d prims\n", rePrimCount);
        TEST_ASSERT(rePrimCount > 0);

        NanousdPrim reRoot = nanousd_defaultprim(reStage);
        if (reRoot)
        {
            std::vector<NanousdPrim> reMeshes;
            findPrimsByType(reRoot, "Mesh", reMeshes);
            printf("  Re-read: %zu mesh(es)\n", reMeshes.size());
            TEST_ASSERT_MSG((int)reMeshes.size() == origMeshCount,
                            "mesh count matches after roundtrip");

            // Compare mesh topology and point data
            for (size_t i = 0; i < reMeshes.size() && i < origMeshes.size(); i++)
            {
                int reP = nanousd_attribarraylen(reMeshes[i], "points");
                int reF = nanousd_attribarraylen(reMeshes[i], "faceVertexCounts");
                char msg[256];
                snprintf(msg, sizeof(msg), "mesh %zu: pts %d==%d", i, reP, origPtCounts[i]);
                TEST_ASSERT_MSG(reP == origPtCounts[i], msg);
                snprintf(msg, sizeof(msg), "mesh %zu: fcs %d==%d", i, reF, origFcCounts[i]);
                TEST_ASSERT_MSG(reF == origFcCounts[i], msg);

                // Compare point values
                if (reP > 0 && reP == origPtCounts[i])
                {
                    std::vector<float> rePts(reP * 3);
                    nanousd_attribarrayv3f(reMeshes[i], "points", rePts.data(), reP);
                    bool match = true;
                    for (int j = 0; j < reP * 3; j++)
                    {
                        if (fabs(rePts[j] - origPtData[i][j]) > 0.001f)
                        {
                            fprintf(stderr, "  Point mismatch [%d]: %f vs %f\n",
                                    j, rePts[j], origPtData[i][j]);
                            match = false;
                            break;
                        }
                    }
                    TEST_ASSERT_MSG(match, "point data matches roundtrip");
                }
            }
        }
        else
        {
            printf("  WARNING: re-read stage has no default prim\n");
        }
        nanousd_close(reStage);
    }
    else
    {
        printf("  WARNING: nanousd could not parse serialized output\n");
        printf("  (expected if output format differs from parser expectations)\n");
    }

    remove(tmpFile);
    nanousd_close(stage);
}

// ===================================================================
//  TEST 17: Multi-file re-read roundtrip — serialize and re-parse
// ===================================================================

static void test_roundtrip_file(const char* dataDir, const char* filename,
                                const char* expectedType, int minPrims)
{
    char label[256];
    snprintf(label, sizeof(label), "roundtrip_%s", filename);
    SECTION(label);

    std::string filepath = std::string(dataDir) + "/" + filename;
    NanousdStage stage = nanousd_open(filepath.c_str());
    TEST_ASSERT_MSG(stage != nullptr, filename);
    if (!stage) return;

    // Count original prims of expected type
    NanousdPrim root = nanousd_defaultprim(stage);
    TEST_ASSERT(root != nullptr);
    if (!root) { nanousd_close(stage); return; }

    std::vector<NanousdPrim> origPrims;
    findPrimsByType(root, expectedType, origPrims);
    int origCount = (int)origPrims.size();
    TEST_ASSERT_MSG(origCount >= minPrims, "enough prims of expected type");

    // Serialize
    std::string serialized = serializeStage(stage);
    TEST_ASSERT(serialized.size() > 100);
    printf("  %s: %zu bytes, %d %s prim(s)\n",
           filename, serialized.size(), origCount, expectedType);

    // Write temp file and re-read
    std::string tmpFile = g_tmp_dir + "/test_roundtrip_" + filename;
    FILE* f = fopen(tmpFile.c_str(), "w");
    TEST_ASSERT_MSG(f != nullptr, "create temp file");
    if (!f) { nanousd_close(stage); return; }
    fwrite(serialized.c_str(), 1, serialized.size(), f);
    fclose(f);

    NanousdStage reStage = nanousd_open(tmpFile.c_str());
    TEST_ASSERT_MSG(reStage != nullptr, "re-read parsed OK");
    if (reStage)
    {
        NanousdPrim reRoot = nanousd_defaultprim(reStage);
        TEST_ASSERT_MSG(reRoot != nullptr, "re-read has default prim");
        if (reRoot)
        {
            std::vector<NanousdPrim> rePrims;
            findPrimsByType(reRoot, expectedType, rePrims);
            char msg[256];
            snprintf(msg, sizeof(msg), "%s count: %zu == %d",
                     expectedType, rePrims.size(), origCount);
            TEST_ASSERT_MSG((int)rePrims.size() == origCount, msg);

            // For Mesh prims, compare point data
            if (strcmp(expectedType, "Mesh") == 0)
            {
                for (size_t i = 0; i < rePrims.size() && i < origPrims.size(); i++)
                {
                    int origNP = nanousd_attribarraylen(origPrims[i], "points");
                    int reNP   = nanousd_attribarraylen(rePrims[i], "points");
                    snprintf(msg, sizeof(msg), "%s mesh %zu pts: %d==%d",
                             filename, i, reNP, origNP);
                    TEST_ASSERT_MSG(reNP == origNP, msg);
                }
            }
        }
        nanousd_close(reStage);
    }

    remove(tmpFile.c_str());
    nanousd_close(stage);
}

static void test_multi_roundtrip(const char* dataDir)
{
    // Re-read roundtrip for each major test file
    test_roundtrip_file(dataDir, "material_network.usda", "Mesh", 2);
    test_roundtrip_file(dataDir, "material_network.usda", "Shader", 5);
    test_roundtrip_file(dataDir, "skeletal_mesh.usda", "Mesh", 1);
    test_roundtrip_file(dataDir, "skeletal_mesh.usda", "Skeleton", 1);
    test_roundtrip_file(dataDir, "lights_cameras.usda", "Camera", 2);
    test_roundtrip_file(dataDir, "curves_points.usda", "BasisCurves", 3);
    test_roundtrip_file(dataDir, "curves_points.usda", "Points", 1);
    test_roundtrip_file(dataDir, "curves.usda", "BasisCurves", 1);
    test_roundtrip_file(dataDir, "complex_mesh.usda", "Mesh", 1);

    // Cornell scene from USDRT test data (richer scene)
    const char* usdrtDir = "runtime/data/usd/tests/usdrt";
    test_roundtrip_file(usdrtDir, "cornell.usda", "Mesh", 4);
}

// ===================================================================
//  TEST 18: Bulk USDA stress — load+serialize+re-read many files
// ===================================================================

static void test_bulk_usda_stress(void)
{
    SECTION("test_bulk_usda_stress");

    // Load USDA files from the USDRT test data directory
    const char* usdrtDir = "runtime/data/usd/tests/usdrt";
    const char* files[] = {
        "triangle.usda", "cube.usda", "hierarchy.usda",
        "curves.usda", "mesh_with_geomsubset.usda",
        "custom_attribute_population.usda",
        "custom_xformable_population.usda",
        "badextent.usda", "color_space_api.usda",
        "hierarchy_fastleaves.usda", "hierarchy_cubric.usda",
        "cornell.usda", "simple_cubes.usda",
        "curve_time_samples.usda", "triangle_timesamples.usda",
        // Phase 45l additions
        "cornell_with_physics.usda",
        "nested_instancing.usda",
        "point_instancer_simple.usda",
        "point_instancer_anim.usda",
        "pointinstancer_instancing.usda",
        "mesh_with_subdiv.usda",
        "mesh_variants.usda",
        "implementation_source_asset.usda",
        "implementation_source_code.usda",
        "xform_component_hierarchy.usda",
        "hierarchy_multi_legacy.usda",
        "rtprimselection.usda",
        "test_custom_default.usda",
        "xforms-timesamples.usda",
        "particlefield.usda",
        "particlefield_static.usda",
        "hierarchy_xform_timesamples.usda",
        "omni_time.usda",
        "xform_with_physics_api.usda",
        "xform_component_hierarchy_large.usda",
        nullptr
    };

    int loaded = 0, serialized = 0, reread = 0;
    for (int i = 0; files[i]; i++)
    {
        char filepath[512];
        snprintf(filepath, sizeof(filepath), "%s/%s", usdrtDir, files[i]);

        NanousdStage stage = nanousd_open(filepath);
        if (!stage || !nanousd_isvalid(stage))
        {
            if (stage) nanousd_close(stage);
            continue;
        }
        loaded++;

        int origPrims = nanousd_nprims(stage);
        TEST_ASSERT(origPrims > 0);

        std::string out = serializeStage(stage);
        if (out.size() > 50)
        {
            serialized++;
            TEST_STR_HAS(out, "#usda 1.0");

            // Balanced braces
            int braces = 0;
            for (char c : out) { if (c == '{') braces++; if (c == '}') braces--; }
            char msg[256];
            snprintf(msg, sizeof(msg), "%s balanced braces", files[i]);
            TEST_ASSERT_MSG(braces == 0, msg);

            // No PXR artifacts
            TEST_STR_LACKS(out, "PXR_NS");
            TEST_STR_LACKS(out, "pxr::");

            // Write and re-read
            char tmpFile[256];
            snprintf(tmpFile, sizeof(tmpFile), "%s/test_bulk_%s", g_tmp_dir.c_str(), files[i]);
            FILE* f = fopen(tmpFile, "w");
            if (f)
            {
                fwrite(out.c_str(), 1, out.size(), f);
                fclose(f);
                NanousdStage reStage = nanousd_open(tmpFile);
                if (reStage)
                {
                    int rePrims = nanousd_nprims(reStage);
                    snprintf(msg, sizeof(msg), "%s re-read prims %d > 0", files[i], rePrims);
                    TEST_ASSERT_MSG(rePrims > 0, msg);
                    reread++;
                    nanousd_close(reStage);
                }
                remove(tmpFile);
            }
        }
        nanousd_close(stage);
    }

    printf("  Bulk: %d loaded, %d serialized, %d re-read OK\n",
           loaded, serialized, reread);
    TEST_ASSERT_MSG(loaded >= 5, "loaded at least 5 files");
    TEST_ASSERT_MSG(serialized >= 5, "serialized at least 5 files");
    TEST_ASSERT_MSG(reread >= 3, "re-read at least 3 files");
}

