// ===================================================================
//  Test: Prim query API
// ===================================================================

static void test_prim_queries(const char* dataDir)
{
    SECTION("test_prim_queries");
    char path[256];
    snprintf(path, sizeof(path), "%s/simple_mesh.usda", dataDir);
    NanousdStage stage = nanousd_open(path);
    TEST_ASSERT_MSG(stage != nullptr, "stage opened");

    NanousdPrim root = nanousd_defaultprim(stage);
    TEST_ASSERT_MSG(root != nullptr, "default prim");

    // typename
    std::string tn = safeStr(nanousd_typename(root));
    TEST_ASSERT_MSG(!tn.empty(), "typename not empty");

    // path
    std::string p = safeStr(nanousd_path(root));
    TEST_ASSERT_MSG(p.find("/") != std::string::npos, "path has /");

    // nchildren
    int nch = nanousd_nchildren(root);
    TEST_ASSERT_MSG(nch >= 0, "nchildren >= 0");

    // child traversal
    for (int i = 0; i < nch; i++)
    {
        NanousdPrim ch = nanousd_child(root, i);
        TEST_ASSERT_MSG(ch != nullptr, "child not null");
        std::string cp = safeStr(nanousd_path(ch));
        TEST_ASSERT_MSG(!cp.empty(), "child has path");

        // parent
        NanousdPrim par = nanousd_parent(ch);
        if (par)
        {
            std::string pp = safeStr(nanousd_path(par));
            TEST_ASSERT_MSG(pp == p, "parent path matches root");
        }
    }

    // nattribs
    int na = nanousd_nattribs(root);
    TEST_ASSERT_MSG(na >= 0, "nattribs >= 0");

    // hasattrib
    if (na > 0)
    {
        std::string aname = safeStr(nanousd_attribname(root, 0));
        int has = nanousd_hasattrib(root, aname.c_str());
        TEST_ASSERT_MSG(has, "hasattrib for first attrib");
        int nohas = nanousd_hasattrib(root, "__nonexistent_attrib__");
        TEST_ASSERT_MSG(!nohas, "!hasattrib for nonexistent");
    }

    // isa (for Mesh or Xform)
    if (tn == "Mesh")
    {
        TEST_ASSERT_MSG(nanousd_isa(root, "Mesh"), "isa Mesh");
        TEST_ASSERT_MSG(!nanousd_isa(root, "Camera"), "!isa Camera");
    }

    nanousd_close(stage);
}

// ===================================================================
//  Test: Time sample API
// ===================================================================

static void test_time_samples()
{
    SECTION("test_time_samples");
    const char* tsFile = "runtime/data/usd/tests/usdrt/triangle_timesamples.usda";
    NanousdStage stage = nanousd_open(tsFile);
    if (!stage || !nanousd_isvalid(stage))
    {
        printf("  SKIP: %s not found\n", tsFile);
        return;
    }

    NanousdPrim dp = nanousd_defaultprim(stage);
    if (!dp && nanousd_nprims(stage) > 0) dp = nanousd_prim(stage, 0);
    TEST_ASSERT_MSG(dp != nullptr, "found prim");

    // Find a prim with time samples by traversing
    // triangle_timesamples has animated points
    std::function<NanousdPrim(NanousdPrim)> findMesh;
    findMesh = [&](NanousdPrim p) -> NanousdPrim {
        std::string t = safeStr(nanousd_typename(p));
        if (t == "Mesh") return p;
        int nc = nanousd_nchildren(p);
        for (int i = 0; i < nc; i++)
        {
            NanousdPrim r = findMesh(nanousd_child(p, i));
            if (r) return r;
        }
        return nullptr;
    };

    NanousdPrim mesh = findMesh(dp);
    if (!mesh)
    {
        printf("  SKIP: no Mesh found in %s\n", tsFile);
        nanousd_close(stage);
        return;
    }

    // Check for time samples on points
    int hasSamples = nanousd_hassamples(mesh, "points");
    if (hasSamples)
    {
        int nkeys = nanousd_nsamplekeys(mesh, "points");
        TEST_ASSERT_MSG(nkeys > 0, "has sample keys");

        double key0 = nanousd_samplekey(mesh, "points", 0);
        // Key should be a valid time code (typically >= 0)
        TEST_ASSERT_MSG(key0 >= 0 || key0 < 1e10, "key0 is valid");

        if (nkeys > 1)
        {
            double key1 = nanousd_samplekey(mesh, "points", 1);
            TEST_ASSERT_MSG(key1 > key0, "key1 > key0");
        }
    }

    // Check for time samples on xformOp:translate or similar
    int na = nanousd_nattribs(mesh);
    for (int i = 0; i < na; i++)
    {
        std::string aname = safeStr(nanousd_attribname(mesh, i));
        if (nanousd_hassamples(mesh, aname.c_str()))
        {
            int nk = nanousd_nsamplekeys(mesh, aname.c_str());
            TEST_ASSERT_MSG(nk > 0, "sampled attr has keys");

            std::string atype = safeStr(nanousd_attribtype(mesh, aname.c_str()));
            if (atype == "float")
            {
                int ok = 0;
                double key = nanousd_samplekey(mesh, aname.c_str(), 0);
                float val = nanousd_samplef(mesh, aname.c_str(), key, &ok);
                (void)val; // Just exercise the API
            }
            break; // one is enough
        }
    }

    nanousd_close(stage);
}

// ===================================================================
//  Test: Path API
// ===================================================================

static void test_path_operations()
{
    SECTION("test_path_operations");

    // Parse a path
    NanousdPath p = nanousd_path_parse("/World/Mesh0");
    TEST_ASSERT_MSG(p != nullptr, "path parsed");

    const char* ps = nanousd_path_str(p);
    TEST_ASSERT_MSG(ps != nullptr, "path_str not null");
    TEST_ASSERT_MSG(std::string(ps) == "/World/Mesh0", "path roundtrip");

    TEST_ASSERT_MSG(nanousd_path_is_absolute(p), "is absolute");
    TEST_ASSERT_MSG(!nanousd_path_is_root(p), "not root");
    TEST_ASSERT_MSG(!nanousd_path_is_property(p), "not property");

    const char* nm = nanousd_path_name(p);
    TEST_ASSERT_MSG(nm != nullptr, "path name not null");
    TEST_ASSERT_MSG(std::string(nm) == "Mesh0", "leaf name is Mesh0");

    // Parent
    NanousdPath parent = nanousd_path_parent(p);
    TEST_ASSERT_MSG(parent != nullptr, "parent not null");
    std::string parentStr = safeStr(nanousd_path_str(parent));
    TEST_ASSERT_MSG(parentStr == "/World", "parent is /World");

    // Append child
    NanousdPath child = nanousd_path_append_child(parent, "NewChild");
    TEST_ASSERT_MSG(child != nullptr, "appended child");
    std::string childStr = safeStr(nanousd_path_str(child));
    TEST_ASSERT_MSG(childStr == "/World/NewChild", "child path correct");

    // Append property
    NanousdPath prop = nanousd_path_append_property(p, "points");
    TEST_ASSERT_MSG(prop != nullptr, "appended property");
    std::string propStr = safeStr(nanousd_path_str(prop));
    TEST_ASSERT_MSG(propStr.find("points") != std::string::npos, "property has 'points'");
    TEST_ASSERT_MSG(nanousd_path_is_property(prop), "property is property");

    // Equality
    NanousdPath p2 = nanousd_path_parse("/World/Mesh0");
    TEST_ASSERT_MSG(nanousd_path_equal(p, p2), "equal paths");

    NanousdPath p3 = nanousd_path_parse("/World/Mesh1");
    TEST_ASSERT_MSG(!nanousd_path_equal(p, p3), "unequal paths");

    // Root path
    NanousdPath root = nanousd_path_parse("/");
    TEST_ASSERT_MSG(nanousd_path_is_root(root), "/ is root");
    TEST_ASSERT_MSG(nanousd_path_is_absolute(root), "/ is absolute");

    // Free all paths
    nanousd_path_free(p);
    nanousd_path_free(parent);
    nanousd_path_free(child);
    nanousd_path_free(prop);
    nanousd_path_free(p2);
    nanousd_path_free(p3);
    nanousd_path_free(root);
}

