// ===================================================================
//  Test: Quaternion and vector scalar reads
// ===================================================================

static void test_quaternion_scalar_reads()
{
    SECTION("test_quaternion_scalar_reads");
    // AbstractPrototypeBase has quatd xformOp:orient
    const char* path = "runtime/data/usd/tests/FabricSceneDelegate/Instancing/input/AbstractPrototypeBase.usda";
    NanousdStage stage = nanousd_open(path);
    if (!stage || !nanousd_isvalid(stage))
    {
        printf("  SKIP: file not found\n");
        if (stage) nanousd_close(stage);
        return;
    }

    // Find a prim with quatd
    int np = nanousd_nprims(stage);
    bool foundQuat = false;
    for (int p = 0; p < np; p++)
    {
        NanousdPrim prim = nanousd_prim(stage, p);
        int na = nanousd_nattribs(prim);
        for (int a = 0; a < na; a++)
        {
            std::string aname = safeStr(nanousd_attribname(prim, a));
            std::string atype = safeStr(nanousd_attribtype(prim, aname.c_str()));
            if (atype == "quatd")
            {
                double q[4];
                int ok = nanousd_attribqd(prim, aname.c_str(), q);
                if (ok)
                {
                    foundQuat = true;
                    // Quaternion should be valid (length ~1)
                    double len = std::sqrt(q[0]*q[0] + q[1]*q[1] + q[2]*q[2] + q[3]*q[3]);
                    TEST_ASSERT_MSG(std::fabs(len - 1.0) < 0.1, "quat length ~1");
                }
            }
            else if (atype == "quatf")
            {
                float q[4];
                int ok = nanousd_attribqf(prim, aname.c_str(), q);
                if (ok) foundQuat = true;
            }
        }
    }
    TEST_ASSERT_MSG(foundQuat, "found and read quaternion attribute");
    nanousd_close(stage);
}

