// ===================================================================

static void test_clear_block_api()
{
    SECTION("test_clear_block_api");

    NanousdStage stage = nanousd_create();
    NanousdPrim prim = nanousd_define_prim(stage, "/World", "Xform");

    // Create and set a value
    nanousd_create_attrib(prim, "testVal", "float");
    nanousd_set_attribf(prim, "testVal", 1.0f);

    int ok = 0;
    float v = nanousd_attribf(prim, "testVal", &ok);
    TEST_ASSERT_MSG(ok, "initial value readable");

    // Clear the default value
    int cleared = nanousd_clear_default(prim, "testVal");
    TEST_ASSERT_MSG(cleared >= 0, "clear_default returns valid");

    // Create and set time samples then clear
    nanousd_create_attrib(prim, "animated", "float");
    nanousd_set_samplef(prim, "animated", 0.0, 1.0f);
    nanousd_set_samplef(prim, "animated", 1.0, 2.0f);

    int clearedSamples = nanousd_clear_samples(prim, "animated");
    TEST_ASSERT_MSG(clearedSamples >= 0, "clear_samples returns valid");

    // Block attribute
    nanousd_create_attrib(prim, "blocked", "float");
    nanousd_set_attribf(prim, "blocked", 5.0f);
    int blocked = nanousd_block_attrib(prim, "blocked");
    TEST_ASSERT_MSG(blocked >= 0, "block_attrib returns valid");

    nanousd_close(stage);
}

