// ===================================================================
//  Test: Prim metadata API
// ===================================================================

static void test_prim_metadata_api()
{
    SECTION("test_prim_metadata_api");

    // Use a file with known prim metadata
    const char* skelFile = "runtime/data/usd/tests/usdrt/skelcylinder_ref.usda";
    NanousdStage stage = nanousd_open(skelFile);
    if (!stage || !nanousd_isvalid(stage))
    {
        printf("  SKIP: file not found\n");
        if (stage) nanousd_close(stage);
        return;
    }

    NanousdPrim dp = nanousd_defaultprim(stage);
    if (dp)
    {
        // Try reading kind metadata
        int ok = 0;
        const char* kind = nanousd_prim_metadatas(dp, "kind", &ok);
        if (ok && kind)
        {
            std::string kindStr(kind);
            TEST_ASSERT_MSG(!kindStr.empty(), "kind not empty");
        }

        // Exercise prim_metadatad (may not be authored)
        double val = nanousd_prim_metadatad(dp, "nonexistent_key", &ok);
        (void)val; // Just exercise

        // isa / hasapi on children
        int nch = nanousd_nchildren(dp);
        for (int i = 0; i < nch; i++)
        {
            NanousdPrim ch = nanousd_child(dp, i);
            std::string tn = safeStr(nanousd_typename(ch));
            if (tn == "SkelRoot")
            {
                TEST_ASSERT_MSG(nanousd_isa(ch, "SkelRoot"), "isa SkelRoot");
            }
            else if (tn == "Mesh")
            {
                TEST_ASSERT_MSG(nanousd_isa(ch, "Mesh"), "isa Mesh");
            }
        }
    }

    nanousd_close(stage);
}

// ===================================================================
//  Test: Zero-copy bulk array access
// ===================================================================

static void test_bulk_array_access(const char* dataDir)
{
    SECTION("test_bulk_array_access");
    char path[256];
    snprintf(path, sizeof(path), "%s/simple_mesh.usda", dataDir);
    NanousdStage stage = nanousd_open(path);
    TEST_ASSERT_MSG(stage != nullptr, "opened");

    // Find a mesh with points
    int np = nanousd_nprims(stage);
    for (int p = 0; p < np; p++)
    {
        NanousdPrim prim = nanousd_prim(stage, p);
        if (safeStr(nanousd_typename(prim)) != "Mesh") continue;

        // Try zero-copy float array access
        int count = 0;
        const float* fdata = nanousd_arraydataf(prim, "points", &count);
        // May return null if not supported — just exercise
        if (fdata && count > 0)
        {
            TEST_ASSERT_MSG(count > 0, "arraydataf count > 0");
            // First value should be finite
            TEST_ASSERT_MSG(std::isfinite(fdata[0]), "first float finite");
        }

        // Try zero-copy int array access
        const int* idata = nanousd_arraydatai(prim, "faceVertexCounts", &count);
        if (idata && count > 0)
        {
            TEST_ASSERT_MSG(count > 0, "arraydatai count > 0");
            TEST_ASSERT_MSG(idata[0] > 0, "first fvc > 0");
        }

        break; // one mesh is enough
    }

    nanousd_close(stage);
}

