// ===================================================================
//  Test: Full write → serialize → re-read cycle (programmatic scene)
// ===================================================================

static void test_programmatic_scene_roundtrip()
{
    SECTION("test_programmatic_scene_roundtrip");

    NanousdStage stage = nanousd_create();
    nanousd_set_stage_metadatad(stage, "metersPerUnit", 0.01);
    nanousd_set_stage_metadatas(stage, "upAxis", "Y");

    // Build a small scene: World > (Mesh + Light + Camera + Material)
    nanousd_define_prim(stage, "/World", "Xform");
    NanousdPrim mesh = nanousd_define_prim(stage, "/World/Mesh", "Mesh");
    NanousdPrim light = nanousd_define_prim(stage, "/World/Light", "DistantLight");
    NanousdPrim cam = nanousd_define_prim(stage, "/World/Camera", "Camera");
    NanousdPrim mat = nanousd_define_prim(stage, "/World/Material", "Material");
    NanousdPrim shader = nanousd_define_prim(stage, "/World/Material/Shader", "Shader");

    // Set mesh data
    float pts[] = {0,0,0, 1,0,0, 0.5f,1,0};
    nanousd_create_attrib(mesh, "points", "point3f[]");
    nanousd_set_attribarrayv3f(mesh, "points", pts, 3);

    int fvc[] = {3};
    nanousd_create_attrib(mesh, "faceVertexCounts", "int[]");
    nanousd_set_attribarrayi(mesh, "faceVertexCounts", fvc, 1);

    int fvi[] = {0, 1, 2};
    nanousd_create_attrib(mesh, "faceVertexIndices", "int[]");
    nanousd_set_attribarrayi(mesh, "faceVertexIndices", fvi, 3);

    // Set light intensity
    nanousd_create_attrib(light, "inputs:intensity", "float");
    nanousd_set_attribf(light, "inputs:intensity", 1000.0f);

    // Set camera
    nanousd_create_attrib(cam, "focalLength", "float");
    nanousd_set_attribf(cam, "focalLength", 50.0f);

    // Material binding
    nanousd_create_rel(mesh, "material:binding");
    nanousd_add_reltarget(mesh, "material:binding", "/World/Material");

    // Serialize
    std::string out = serializeStage(stage);
    TEST_STR_HAS(out, "def Mesh");
    TEST_STR_HAS(out, "def DistantLight");
    TEST_STR_HAS(out, "def Camera");
    TEST_STR_HAS(out, "def Material");
    TEST_STR_HAS(out, "def Shader");
    TEST_STR_HAS(out, "point3f[] points");
    TEST_STR_HAS(out, "int[] faceVertexCounts");
    TEST_STR_HAS(out, "inputs:intensity");
    TEST_STR_HAS(out, "focalLength");
    TEST_STR_HAS(out, "material:binding");

    // Write to disk and re-read
    const char* tmpFile = tmp_path("test_programmatic_scene.usda");
    FILE* f = fopen(tmpFile, "w");
    fwrite(out.c_str(), 1, out.size(), f);
    fclose(f);

    NanousdStage reStage = nanousd_open(tmpFile);
    TEST_ASSERT_MSG(reStage != nullptr, "re-opened");
    TEST_ASSERT_MSG(nanousd_isvalid(reStage), "re-valid");

    int rePrims = nanousd_nprims(reStage);
    TEST_ASSERT_MSG(rePrims >= 5, "re-read >= 5 prims");

    // Find the mesh in re-read and verify points
    for (int p = 0; p < rePrims; p++)
    {
        NanousdPrim rp = nanousd_prim(reStage, p);
        if (safeStr(nanousd_typename(rp)) == "Mesh")
        {
            int ptsLen = nanousd_attribarraylen(rp, "points");
            TEST_ASSERT_MSG(ptsLen == 3, "re-read 3 points");
            float rePts[9];
            int got = nanousd_attribarrayv3f(rp, "points", rePts, 3);
            TEST_ASSERT_MSG(got == 3, "read 3 points back");
            TEST_ASSERT_MSG(std::fabs(rePts[3] - 1.0f) < 1e-5f, "pt[1].x = 1");
            break;
        }
    }

    nanousd_close(reStage);
    remove(tmpFile);
    nanousd_close(stage);
}

// ===================================================================
//  Test: Double-precision array write and read
// ===================================================================

static void test_double_array_write()
{
    SECTION("test_double_array_write");

    NanousdStage stage = nanousd_create();
    NanousdPrim prim = nanousd_define_prim(stage, "/World/Mesh", "Mesh");

    // Write double3 array (e.g., extent)
    double v3d[] = {0, 0, 0, 1, 1, 1};
    nanousd_create_attrib(prim, "extent", "float3[]");
    nanousd_set_attribarrayv3d(prim, "extent", v3d, 2);

    // Read back
    double readV3d[6];
    int got = nanousd_attribarrayv3d(prim, "extent", readV3d, 2);
    if (got == 2)
    {
        TEST_ASSERT_MSG(std::fabs(readV3d[3] - 1.0) < 1e-10, "extent[1].x = 1");
    }

    // Write float array
    float fArr[] = {0.1f, 0.2f, 0.3f, 0.4f};
    nanousd_create_attrib(prim, "widths", "float[]");
    nanousd_set_attribarrayf(prim, "widths", fArr, 4);

    float readF[4];
    got = nanousd_attribarrayf(prim, "widths", readF, 4);
    if (got == 4)
    {
        TEST_ASSERT_MSG(std::fabs(readF[0] - 0.1f) < 1e-6f, "widths[0] = 0.1");
        TEST_ASSERT_MSG(std::fabs(readF[3] - 0.4f) < 1e-6f, "widths[3] = 0.4");
    }

    // Write double array
    double dArr[] = {1.1, 2.2, 3.3};
    nanousd_create_attrib(prim, "myDoubles", "double[]");
    nanousd_set_attribarrayd(prim, "myDoubles", dArr, 3);

    double readD[3];
    got = nanousd_attribarrayd(prim, "myDoubles", readD, 3);
    if (got == 3)
    {
        TEST_ASSERT_MSG(std::fabs(readD[1] - 2.2) < 1e-10, "doubles[1] = 2.2");
    }

    nanousd_close(stage);
}

// ===================================================================
//  Test: Time sample vector write/read
// ===================================================================

static void test_timesample_vector_write()
{
    SECTION("test_timesample_vector_write");

    NanousdStage stage = nanousd_create();
    NanousdPrim prim = nanousd_define_prim(stage, "/World", "Xform");

    // Write vec3f time samples (animated translate)
    float t0[] = {0, 0, 0};
    float t1[] = {10, 0, 0};
    nanousd_create_attrib(prim, "xformOp:translate", "double3");
    double d0[] = {0, 0, 0};
    double d1[] = {10, 0, 0};
    nanousd_set_samplev3d(prim, "xformOp:translate", 0.0, d0);
    nanousd_set_samplev3d(prim, "xformOp:translate", 24.0, d1);

    // Read back
    TEST_ASSERT_MSG(nanousd_hassamples(prim, "xformOp:translate"), "has samples");
    int nkeys = nanousd_nsamplekeys(prim, "xformOp:translate");
    TEST_ASSERT_MSG(nkeys == 2, "2 keys");

    double readV[3];
    int ok = nanousd_samplev3d(prim, "xformOp:translate", 0.0, readV);
    TEST_ASSERT_MSG(ok, "read sample v3d at t=0");
    TEST_ASSERT_MSG(std::fabs(readV[0]) < 1e-6, "translate at t=0 = 0");

    ok = nanousd_samplev3d(prim, "xformOp:translate", 24.0, readV);
    TEST_ASSERT_MSG(ok, "read sample v3d at t=24");
    TEST_ASSERT_MSG(std::fabs(readV[0] - 10.0) < 1e-6, "translate at t=24 = 10");

    // Time sample for double scalar
    nanousd_create_attrib(prim, "myAnimD", "double");
    nanousd_set_sampled(prim, "myAnimD", 0.0, 100.0);
    nanousd_set_sampled(prim, "myAnimD", 12.0, 200.0);

    int okd = 0;
    double vd = nanousd_sampled(prim, "myAnimD", 0.0, &okd);
    TEST_ASSERT_MSG(okd, "read double sample");
    TEST_ASSERT_MSG(std::fabs(vd - 100.0) < 1e-6, "double sample = 100");

    nanousd_close(stage);
}

