// ===================================================================
//  Test: Error handling and edge cases
// ===================================================================

static void test_error_handling()
{
    SECTION("test_error_handling");

    // Open non-existent file
    NanousdStage bad = nanousd_open("/nonexistent/file.usda");
    if (bad)
    {
        TEST_ASSERT_MSG(!nanousd_isvalid(bad), "nonexistent file not valid");
        nanousd_close(bad);
    }

    // Open null path
    NanousdStage nullStage = nanousd_open(nullptr);
    // Should not crash
    (void)nullStage;
    if (nullStage) nanousd_close(nullStage);

    // Operations on null prim
    int na = nanousd_nattribs(nullptr);
    TEST_ASSERT_MSG(na <= 0, "nattribs(null) <= 0");

    int nc = nanousd_nchildren(nullptr);
    TEST_ASSERT_MSG(nc <= 0, "nchildren(null) <= 0");

    const char* tp = nanousd_typename(nullptr);
    // Should return empty or null without crash
    (void)tp;

    // Read from nonexistent attribute
    NanousdStage stage = nanousd_create();
    NanousdPrim prim = nanousd_define_prim(stage, "/World", "Xform");

    int ok = 0;
    float noval = nanousd_attribf(prim, "nonexistent", &ok);
    TEST_ASSERT_MSG(!ok, "nonexistent attrib not ok");
    (void)noval;

    int alen = nanousd_attribarraylen(prim, "nonexistent");
    TEST_ASSERT_MSG(alen <= 0, "nonexistent array len <= 0");

    // hasattrib for nonexistent
    TEST_ASSERT_MSG(!nanousd_hasattrib(prim, "nonexistent"), "!hasattrib nonexistent");

    // hasrel for nonexistent
    TEST_ASSERT_MSG(!nanousd_hasrel(prim, "nonexistent:rel"), "!hasrel nonexistent");

    // Path parse edge cases
    NanousdPath emptyP = nanousd_path_parse("");
    if (emptyP) nanousd_path_free(emptyP);

    NanousdPath nullP = nanousd_path_parse(nullptr);
    if (nullP) nanousd_path_free(nullP);

    nanousd_close(stage);
}

