    nanousd_create_attrib(prim, "anInt", "int"); nanousd_set_attribi(prim, "anInt", 7);
    nanousd_create_attrib(prim, "aBool", "bool"); nanousd_set_attribb(prim, "aBool", 1);
    nanousd_create_attrib(prim, "aToken", "token"); nanousd_set_attribs(prim, "aToken", "catmullClark");

    float c3f[] = {0.5f, 0.6f, 0.7f};
