// ===================================================================
//  Test: Deep hierarchy traversal
// ===================================================================

static void test_deep_hierarchy()
{
    SECTION("test_deep_hierarchy");

    NanousdStage stage = nanousd_create();

    // Create a 10-level deep hierarchy
    std::string path = "";
    for (int i = 0; i < 10; i++)
    {
        char name[32];
        snprintf(name, sizeof(name), "/Level%d", i);
        path += name;
        nanousd_define_prim(stage, path.c_str(), "Xform");
    }

    // Traverse from root
    NanousdPrim current = nanousd_primpath(stage, "/Level0");
    TEST_ASSERT_MSG(current != nullptr, "root found");

    int depth = 0;
    while (current && nanousd_nchildren(current) > 0)
    {
        current = nanousd_child(current, 0);
        depth++;
    }
    TEST_ASSERT_MSG(depth >= 8, "traversed at least 8 levels deep");

    // Serialize and check nesting
    std::string out = serializeStage(stage);
    int braces = 0;
    for (char c : out) { if (c == '{') braces++; if (c == '}') braces--; }
    TEST_ASSERT_MSG(braces == 0, "balanced braces in deep hierarchy");

    // Should have 10 Xform definitions
    size_t xfCount = 0;
    size_t pos = 0;
    while ((pos = out.find("def Xform", pos)) != std::string::npos)
    {
        xfCount++;
        pos++;
    }
    TEST_ASSERT_MSG(xfCount >= 10, "10+ Xform defs");

    nanousd_close(stage);
}

// ===================================================================
