    // Special characters
    nanousd_create_attrib(prim, "specialStr", "token");
    nanousd_set_attribs(prim, "specialStr", "path/to/file.mdl");

    v = nanousd_attribs(prim, "specialStr", &ok);
    TEST_ASSERT_MSG(ok, "special string ok");
