// ===================================================================
//  Test: Attribute enumeration — nattribs + attribname + attribtype + hasattrib
// ===================================================================

static void test_attrib_enumeration()
{
    SECTION("test_attrib_enumeration");

    // Use simple_mesh.usda which has a Mesh prim with known attributes
    const char* filePath =
        "runtime/source/plugins/usdrt.hydra.usd_writer/tests/data/simple_mesh.usda";
    NanousdStage stage = nanousd_open(filePath);
    TEST_ASSERT_MSG(stage != nullptr, "opened simple_mesh.usda for attrib enum");
    if (!stage) return;
    TEST_ASSERT_MSG(nanousd_isvalid(stage), "attrib_enumeration stage valid");

    // Find a Mesh prim via recursive search
    NanousdPrim root = nanousd_defaultprim(stage);
    TEST_ASSERT_MSG(root != nullptr, "defaultprim exists");
    if (!root) { nanousd_close(stage); return; }

    std::vector<NanousdPrim> meshes;
    findPrimsByType(root, "Mesh", meshes);
    TEST_ASSERT_MSG(!meshes.empty(), "found at least one Mesh prim");
    if (meshes.empty()) { nanousd_close(stage); return; }

    NanousdPrim mesh = meshes[0];

    // Enumerate all attributes
    int na = nanousd_nattribs(mesh);
    TEST_ASSERT_MSG(na > 0, "mesh has at least 1 attribute");
    printf("  Mesh has %d attributes\n", na);

    // For each attribute: verify non-empty name, valid type string, hasattrib returns true
    int checked = 0;
    for (int i = 0; i < na; i++)
    {
        const char* rawName = nanousd_attribname(mesh, i);
        TEST_ASSERT_MSG(rawName != nullptr, "attribname not null");
        std::string aname = safeStr(rawName);
        TEST_ASSERT_MSG(!aname.empty(), "attrib name not empty");

        // hasattrib must return true for each enumerated name
        int has = nanousd_hasattrib(mesh, aname.c_str());
        TEST_ASSERT_MSG(has, "hasattrib true for enumerated attrib");

        // attribtype must return a non-empty string
        const char* rawType = nanousd_attribtype(mesh, aname.c_str());
        std::string atype = safeStr(rawType);
        TEST_ASSERT_MSG(!atype.empty(), "attrib type not empty");

        // Type string must be reasonable length (< 30 chars)
        TEST_ASSERT_MSG(atype.size() < 30, "attrib type string reasonable length");

        checked++;
    }
    TEST_ASSERT_MSG(checked == na, "checked all attributes");

    // For a Mesh we expect specific attributes: faceVertexCounts, faceVertexIndices, points
    TEST_ASSERT_MSG(nanousd_hasattrib(mesh, "faceVertexCounts"),   "mesh has faceVertexCounts");
    TEST_ASSERT_MSG(nanousd_hasattrib(mesh, "faceVertexIndices"),  "mesh has faceVertexIndices");
    TEST_ASSERT_MSG(nanousd_hasattrib(mesh, "points"),             "mesh has points");

    // hasattrib should return false for a nonexistent name
    TEST_ASSERT_MSG(!nanousd_hasattrib(mesh, "__totally_nonexistent_xyz__"),
                    "hasattrib false for nonexistent");

    // Verify type strings for well-known mesh attributes
    std::string fvcType = safeStr(nanousd_attribtype(mesh, "faceVertexCounts"));
    TEST_ASSERT_MSG(!fvcType.empty(), "faceVertexCounts has type");
    TEST_ASSERT_MSG(fvcType.find("int") != std::string::npos,
                    "faceVertexCounts type contains 'int'");

    std::string ptsType = safeStr(nanousd_attribtype(mesh, "points"));
    TEST_ASSERT_MSG(!ptsType.empty(), "points has type");

    // Also verify attribarraylen works for the enumerated array attributes
    int npts = nanousd_attribarraylen(mesh, "points");
    TEST_ASSERT_MSG(npts > 0, "points array has elements");

    int nfvc = nanousd_attribarraylen(mesh, "faceVertexCounts");
    TEST_ASSERT_MSG(nfvc > 0, "faceVertexCounts array has elements");

    printf("  Attributes enumerated: %d, points len: %d, fvc len: %d\n",
           na, npts, nfvc);

    nanousd_close(stage);
}

// ===================================================================
//  Test: Cornell deep validation
// ===================================================================

static void test_cornell_deep_validation()
{
    SECTION("test_cornell_deep_validation");

    const char* path = "runtime/data/usd/tests/usdrt/cornell.usda";
    NanousdStage stage = nanousd_open(path);
    TEST_ASSERT_MSG(stage != nullptr, "open cornell.usda");
    if (!stage) return;

    int np = nanousd_nprims(stage);
    TEST_ASSERT_MSG(np >= 39, "cornell has 39+ prims");
    printf("  cornell: %d prims\n", np);

    // Find a Mesh prim and verify topology attributes
    std::vector<NanousdPrim> meshes;
    for (int i = 0; i < np; i++)
    {
        NanousdPrim p = nanousd_prim(stage, i);
        if (!p) continue;
        std::string t = safeStr(nanousd_typename(p));
        if (t == "Mesh") meshes.push_back(p);
    }
    TEST_ASSERT_MSG(!meshes.empty(), "cornell has at least one Mesh prim");

    if (!meshes.empty())
    {
        NanousdPrim mesh = meshes[0];
        TEST_ASSERT_MSG(nanousd_hasattrib(mesh, "points"), "mesh has points");
        TEST_ASSERT_MSG(nanousd_hasattrib(mesh, "faceVertexCounts"), "mesh has faceVertexCounts");
        TEST_ASSERT_MSG(nanousd_hasattrib(mesh, "faceVertexIndices"), "mesh has faceVertexIndices");

        int npts = nanousd_attribarraylen(mesh, "points");
        TEST_ASSERT_MSG(npts > 0, "mesh points array non-empty");

        int nfvc = nanousd_attribarraylen(mesh, "faceVertexCounts");
        TEST_ASSERT_MSG(nfvc > 0, "mesh faceVertexCounts array non-empty");

        int nfvi = nanousd_attribarraylen(mesh, "faceVertexIndices");
        TEST_ASSERT_MSG(nfvi > 0, "mesh faceVertexIndices array non-empty");

        printf("  mesh[0]: %d points, %d faces, %d indices\n", npts, nfvc, nfvi);
    }

    // Check at least one light exists
    bool hasLight = false;
    for (int i = 0; i < np; i++)
    {
        NanousdPrim p = nanousd_prim(stage, i);
        if (!p) continue;
        std::string t = safeStr(nanousd_typename(p));
        if (t.find("Light") != std::string::npos)
        {
            hasLight = true;
            break;
        }
    }
    TEST_ASSERT_MSG(hasLight, "cornell has at least one Light prim");

    // Serialize and verify
    std::string out = serializeStage(stage);
    TEST_ASSERT_MSG(out.size() > 5000, "cornell serialization > 5000 bytes");
    printf("  serialized %zu bytes\n", out.size());

    int opens = 0, closes = 0;
    for (char c : out) { if (c == '{') opens++; else if (c == '}') closes++; }
    TEST_ASSERT_MSG(opens == closes, "cornell serialization has balanced braces");

    nanousd_close(stage);
}

