    if (out.find("xformOp:scale") != std::string::npos) xformOpCount++;
    if (out.find("xformOpOrder") != std::string::npos) xformOpCount++;
    TEST_ASSERT_MSG(xformOpCount >= 3, "at least 3/4 xformOp names in serialized output");
    printf("  found %d/4 xformOp names in serialization\n", xformOpCount);

    // Write, reopen, reverify
