// ===================================================================
//  Test: scalar array write + readback (float[], double[], int[])
// ===================================================================

static void test_array_write_reads()
{
    SECTION("test_array_write_reads");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/ArrPrim", "Mesh");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");
    if (!prim) { nanousd_close(stage); return; }

    // float[] write + read
    float wf[] = {1.0f, 2.0f, 3.0f};
    nanousd_create_attrib(prim, "myFloatArr", "float[]");
    int sfok = nanousd_set_attribarrayf(prim, "myFloatArr", wf, 3);
    TEST_ASSERT_MSG(sfok, "set_attribarrayf returned ok");

    int flen = nanousd_attribarraylen(prim, "myFloatArr");
    TEST_ASSERT_MSG(flen == 3, "attribarraylen for float[] == 3");

    float rf[3] = {};
    int gf = nanousd_attribarrayf(prim, "myFloatArr", rf, 3);
    TEST_ASSERT_MSG(gf == 3, "attribarrayf returned 3 elements");
    if (gf == 3)
    {
        TEST_ASSERT_MSG(std::fabs(rf[0] - 1.0f) < 1e-6f, "float[0] == 1.0");
        TEST_ASSERT_MSG(std::fabs(rf[1] - 2.0f) < 1e-6f, "float[1] == 2.0");
        TEST_ASSERT_MSG(std::fabs(rf[2] - 3.0f) < 1e-6f, "float[2] == 3.0");
    }

    // double[] write + read
    double wd[] = {1.0, 2.0, 3.0};
    nanousd_create_attrib(prim, "myDblArr", "double[]");
    int sdok = nanousd_set_attribarrayd(prim, "myDblArr", wd, 3);
    TEST_ASSERT_MSG(sdok, "set_attribarrayd returned ok");

    int dlen = nanousd_attribarraylen(prim, "myDblArr");
    TEST_ASSERT_MSG(dlen == 3, "attribarraylen for double[] == 3");

    double rd[3] = {};
    int gd = nanousd_attribarrayd(prim, "myDblArr", rd, 3);
    TEST_ASSERT_MSG(gd == 3, "attribarrayd returned 3 elements");
    if (gd == 3)
    {
        TEST_ASSERT_MSG(std::fabs(rd[0] - 1.0) < 1e-9, "double[0] == 1.0");
        TEST_ASSERT_MSG(std::fabs(rd[1] - 2.0) < 1e-9, "double[1] == 2.0");
        TEST_ASSERT_MSG(std::fabs(rd[2] - 3.0) < 1e-9, "double[2] == 3.0");
    }

    // int[] write + read
    int wi[] = {10, 20, 30};
    nanousd_create_attrib(prim, "myIntArr", "int[]");
    int siok = nanousd_set_attribarrayi(prim, "myIntArr", wi, 3);
    TEST_ASSERT_MSG(siok, "set_attribarrayi returned ok");

    int ilen = nanousd_attribarraylen(prim, "myIntArr");
    TEST_ASSERT_MSG(ilen == 3, "attribarraylen for int[] == 3");

    int ri[3] = {};
    int gi = nanousd_attribarrayi(prim, "myIntArr", ri, 3);
    TEST_ASSERT_MSG(gi == 3, "attribarrayi returned 3 elements");
    if (gi == 3)
    {
        TEST_ASSERT_MSG(ri[0] == 10, "int[0] == 10");
        TEST_ASSERT_MSG(ri[1] == 20, "int[1] == 20");
        TEST_ASSERT_MSG(ri[2] == 30, "int[2] == 30");
    }

    nanousd_close(stage);
}

// ===================================================================
