    if (!prim) { nanousd_close(stage); return; }

    nanousd_create_attrib(prim, "primvars:color", "color3f");
    float c[3] = {1.0f, 0.0f, 0.0f};
    nanousd_set_attribv3f(prim, "primvars:color", c);

    // Block the attribute
    int blocked = nanousd_block_attrib(prim, "primvars:color");
    TEST_ASSERT_MSG(blocked, "block_attrib returned success");

    // After blocking, reading should return ok=0 or default
    float out[3] = {};
