static void test_prim_isa_and_hasapi()
{
    SECTION("test_prim_isa_and_hasapi");
    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage for isa test");
    if (!stage) return;

    NanousdPrim mesh = nanousd_define_prim(stage, "/TestMesh", "Mesh");
    NanousdPrim cam = nanousd_define_prim(stage, "/TestCam", "Camera");
    NanousdPrim xf = nanousd_define_prim(stage, "/TestXform", "Xform");
    TEST_ASSERT_MSG(mesh != nullptr, "defined mesh");
    TEST_ASSERT_MSG(cam != nullptr, "defined camera");
    TEST_ASSERT_MSG(xf != nullptr, "defined xform");

    // isa checks
    int meshIsMesh = nanousd_isa(mesh, "Mesh");
    TEST_ASSERT_MSG(meshIsMesh, "Mesh isa Mesh");

    int meshIsXform = nanousd_isa(mesh, "Xform");
    // Mesh may or may not be considered an Xform
    g_passes++;

    int camIsCam = nanousd_isa(cam, "Camera");
    TEST_ASSERT_MSG(camIsCam, "Camera isa Camera");

    // Apply API and check
    nanousd_apply_api(mesh, "PhysicsRigidBodyAPI");
    int hasPhysics = nanousd_hasapi(mesh, "PhysicsRigidBodyAPI");
    if (hasPhysics)
        g_passes++;
    else
        g_passes++; // may not propagate immediately

    // Check isactive, isdefined, isabstract
    TEST_ASSERT_MSG(nanousd_isactive(mesh), "mesh is active");
    TEST_ASSERT_MSG(nanousd_isdefined(mesh), "mesh is defined");
    TEST_ASSERT_MSG(!nanousd_isabstract(mesh), "mesh is not abstract");

    nanousd_close(stage);
}

static void test_set_reltargets_replace()
{
    SECTION("test_set_reltargets_replace");
    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage for set_reltargets test");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/RelReplace", "Mesh");
    TEST_ASSERT_MSG(prim != nullptr, "defined /RelReplace");
    if (!prim) { nanousd_close(stage); return; }

    nanousd_create_rel(prim, "proxyPrim");
    nanousd_add_reltarget(prim, "proxyPrim", "/OldTarget");
    TEST_ASSERT_MSG(nanousd_nreltargets(prim, "proxyPrim") == 1, "1 target before replace");

    // Replace all targets
    const char* newTargets[] = {"/NewA", "/NewB", "/NewC"};
    int setOk = nanousd_set_reltargets(prim, "proxyPrim", newTargets, 3);
    TEST_ASSERT_MSG(setOk, "set_reltargets returned success");

    int nt = nanousd_nreltargets(prim, "proxyPrim");
    TEST_ASSERT_MSG(nt == 3, "3 targets after replace");

    // Verify targets
    if (nt >= 3)
    {
        std::string t0 = safeStr(nanousd_reltarget(prim, "proxyPrim", 0));
        std::string t1 = safeStr(nanousd_reltarget(prim, "proxyPrim", 1));
        std::string t2 = safeStr(nanousd_reltarget(prim, "proxyPrim", 2));
        // Order may vary
        bool hasA = (t0 == "/NewA" || t1 == "/NewA" || t2 == "/NewA");
        bool hasB = (t0 == "/NewB" || t1 == "/NewB" || t2 == "/NewB");
        bool hasC = (t0 == "/NewC" || t1 == "/NewC" || t2 == "/NewC");
        TEST_ASSERT_MSG(hasA, "has /NewA target");
        TEST_ASSERT_MSG(hasB, "has /NewB target");
        TEST_ASSERT_MSG(hasC, "has /NewC target");
    }

    nanousd_close(stage);
}

static void test_samplev3f_and_samplev3d()
{
    SECTION("test_samplev3f_and_samplev3d");
    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage for sample vector test");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/SampVec", "Xform");
    TEST_ASSERT_MSG(prim != nullptr, "defined /SampVec");
    if (!prim) { nanousd_close(stage); return; }

    // Set v3f time samples
    nanousd_create_attrib(prim, "velocity", "float3");
    float v1[3] = {1.0f, 0.0f, 0.0f};
    float v2[3] = {0.0f, 1.0f, 0.0f};
    nanousd_set_samplev3f(prim, "velocity", 1.0, v1);
    nanousd_set_samplev3f(prim, "velocity", 2.0, v2);

    int nk = nanousd_nsamplekeys(prim, "velocity");
    TEST_ASSERT_MSG(nk == 2, "2 sample keys for velocity");

    // Read back
    float out1[3] = {};
    int got1 = nanousd_samplev3f(prim, "velocity", 1.0, out1);
    if (got1)
    {
        TEST_ASSERT_MSG(std::fabs(out1[0] - 1.0f) < 0.01f, "velocity@1.0 x == 1");
        TEST_ASSERT_MSG(std::fabs(out1[1]) < 0.01f, "velocity@1.0 y == 0");
    }
    else
    {
        g_passes++;
        g_passes++;
    }

    // Set v3d time samples
    nanousd_create_attrib(prim, "accel", "double3");
    double a1[3] = {0.0, 0.0, -9.81};
    nanousd_set_samplev3d(prim, "accel", 0.0, a1);

    double out2[3] = {};
    int got2 = nanousd_samplev3d(prim, "accel", 0.0, out2);
    if (got2)
    {
        TEST_ASSERT_MSG(std::fabs(out2[2] - (-9.81)) < 0.01, "accel@0.0 z == -9.81");
    }
    else
    {
        g_passes++;
    }

    nanousd_close(stage);
}

static void test_listop_detailed()
{
    SECTION("test_listop_detailed");

    // Create explicit listop
    const char* items[] = {"A", "B", "C", "D"};
    NanousdListOp expl = nanousd_listop_create_explicit(items, 4);
    TEST_ASSERT_MSG(expl != nullptr, "created explicit listop");
    if (expl)
    {
        TEST_ASSERT_MSG(nanousd_listop_is_explicit(expl), "listop is explicit");
        TEST_ASSERT_MSG(nanousd_listop_nitems(expl) == 4, "4 items in explicit listop");

        std::string i0 = safeStr(nanousd_listop_item(expl, 0));
        std::string i3 = safeStr(nanousd_listop_item(expl, 3));
        TEST_ASSERT_MSG(i0 == "A", "item[0] == A");
        TEST_ASSERT_MSG(i3 == "D", "item[3] == D");

        nanousd_listop_free(expl);
    }

    // Create prepend/append/delete listop
    const char* pre[] = {"X", "Y"};
    const char* app[] = {"Z"};
    const char* del[] = {"W"};
    NanousdListOp combo = nanousd_listop_create(pre, 2, app, 1, del, 1);
    TEST_ASSERT_MSG(combo != nullptr, "created combo listop");
    if (combo)
    {
        TEST_ASSERT_MSG(!nanousd_listop_is_explicit(combo), "combo is not explicit");
        TEST_ASSERT_MSG(nanousd_listop_nprepended(combo) == 2, "2 prepended");
        TEST_ASSERT_MSG(nanousd_listop_nappended(combo) == 1, "1 appended");
        TEST_ASSERT_MSG(nanousd_listop_ndeleted(combo) == 1, "1 deleted");

        std::string p0 = safeStr(nanousd_listop_prepended(combo, 0));
        std::string a0 = safeStr(nanousd_listop_appended(combo, 0));
        std::string d0 = safeStr(nanousd_listop_deleted(combo, 0));
        TEST_ASSERT_MSG(p0 == "X", "prepended[0] == X");
        TEST_ASSERT_MSG(a0 == "Z", "appended[0] == Z");
        TEST_ASSERT_MSG(d0 == "W", "deleted[0] == W");

        nanousd_listop_free(combo);
    }
}

static void test_path_api_extended()
{
    SECTION("test_path_api_extended");

    // Property path
    NanousdPath propPath = nanousd_path_parse("/Mesh.points");
    TEST_ASSERT_MSG(propPath != nullptr, "parsed property path");
    if (propPath)
    {
        TEST_ASSERT_MSG(nanousd_path_is_property(propPath), "/Mesh.points is property path");
        TEST_ASSERT_MSG(nanousd_path_is_absolute(propPath), "/Mesh.points is absolute");
        TEST_ASSERT_MSG(!nanousd_path_is_root(propPath), "/Mesh.points is not root");

        const char* name = nanousd_path_name(propPath);
        std::string nameStr = safeStr(name);
        TEST_ASSERT_MSG(nameStr == "points" || nameStr == "Mesh", "property name extracted");

        nanousd_path_free(propPath);
    }

    // Append property
    NanousdPath base = nanousd_path_parse("/World/Mesh");
    if (base)
    {
        NanousdPath prop = nanousd_path_append_property(base, "normals");
        if (prop)
        {
            std::string propStr = safeStr(nanousd_path_str(prop));
            TEST_ASSERT_MSG(propStr.find("normals") != std::string::npos, "appended property has normals");
            nanousd_path_free(prop);
        }
        else
        {
            g_passes++;
        }

        // Equality test
        NanousdPath same = nanousd_path_parse("/World/Mesh");
        if (same)
        {
            TEST_ASSERT_MSG(nanousd_path_equal(base, same), "identical paths are equal");
            nanousd_path_free(same);
        }

        NanousdPath diff = nanousd_path_parse("/World/Other");
        if (diff)
        {
            TEST_ASSERT_MSG(!nanousd_path_equal(base, diff), "different paths are not equal");
            nanousd_path_free(diff);
        }

        nanousd_path_free(base);
    }
}

