// ===================================================================
//  Test: 10 float time samples at different times
// ===================================================================

static void test_samplef_at_multiple_times()
{
    SECTION("test_samplef_at_multiple_times");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/SampleF", "Xform");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");

    nanousd_create_attrib(prim, "anim", "float");

    // Set 10 time samples: t=0..9, value = t * 1.5
    for (int t = 0; t < 10; t++)
    {
        float val = (float)t * 1.5f;
        int ok = nanousd_set_samplef(prim, "anim", (double)t, val);
        char buf[64]; snprintf(buf, sizeof(buf), "set samplef at t=%d", t);
        TEST_ASSERT_MSG(ok, buf);
    }

    TEST_ASSERT_MSG(nanousd_nsamplekeys(prim, "anim") == 10, "10 sample keys");

    // Read each back
    for (int t = 0; t < 10; t++)
    {
        int ok = 0;
        float val = nanousd_samplef(prim, "anim", (double)t, &ok);
        char buf[64]; snprintf(buf, sizeof(buf), "samplef read at t=%d", t);
        TEST_ASSERT_MSG(ok, buf);
        float expected = (float)t * 1.5f;
        snprintf(buf, sizeof(buf), "samplef value at t=%d (got %.3f, expected %.3f)", t, val, expected);
        TEST_ASSERT_MSG(std::fabs(val - expected) < 1e-5f, buf);
    }

    printf("  10 float time samples OK\n");
    nanousd_close(stage);
}

