// ===================================================================
//  Test: hassamples returns 0 before, 1 after setting samples
// ===================================================================

static void test_hassamples_before_after()
{
    SECTION("test_hassamples_before_after");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/HasSamples", "Xform");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");

    // Create attrib with only a default value
    nanousd_create_attrib(prim, "val", "float");
    nanousd_set_attribf(prim, "val", 1.0f);

    int hasBefore = nanousd_hassamples(prim, "val");
    TEST_ASSERT_MSG(hasBefore == 0, "hassamples == 0 before setting samples");

    // Now set a time sample
    nanousd_set_samplef(prim, "val", 1.0, 2.0f);

    int hasAfter = nanousd_hassamples(prim, "val");
    TEST_ASSERT_MSG(hasAfter == 1, "hassamples == 1 after setting sample");

    // Also check nsamplekeys consistency
    int nkeys = nanousd_nsamplekeys(prim, "val");
    TEST_ASSERT_MSG(nkeys >= 1, "nsamplekeys >= 1 after setting sample");

    printf("  hassamples before/after OK\n");
    nanousd_close(stage);
}

// ===================================================================
//  Test: samplekey ordering — set out of order, read sorted
// ===================================================================

static void test_samplekey_ordering()
{
    SECTION("test_samplekey_ordering");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/KeyOrder", "Xform");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");

    nanousd_create_attrib(prim, "x", "float");

    // Set samples out of order: 3.0, 1.0, 2.0
    nanousd_set_samplef(prim, "x", 3.0, 30.0f);
    nanousd_set_samplef(prim, "x", 1.0, 10.0f);
    nanousd_set_samplef(prim, "x", 2.0, 20.0f);

    int nkeys = nanousd_nsamplekeys(prim, "x");
    TEST_ASSERT_MSG(nkeys == 3, "3 sample keys");

    // Keys should come back sorted: 1.0, 2.0, 3.0
    double k0 = nanousd_samplekey(prim, "x", 0);
    double k1 = nanousd_samplekey(prim, "x", 1);
    double k2 = nanousd_samplekey(prim, "x", 2);

    TEST_ASSERT_MSG(std::fabs(k0 - 1.0) < 1e-6, "key[0] == 1.0 (sorted)");
    TEST_ASSERT_MSG(std::fabs(k1 - 2.0) < 1e-6, "key[1] == 2.0 (sorted)");
    TEST_ASSERT_MSG(std::fabs(k2 - 3.0) < 1e-6, "key[2] == 3.0 (sorted)");

    // Also verify values match the correct times
    int ok = 0;
    float v1 = nanousd_samplef(prim, "x", 1.0, &ok);
    TEST_ASSERT_MSG(ok && std::fabs(v1 - 10.0f) < 1e-5f, "value at t=1 == 10");
    float v2 = nanousd_samplef(prim, "x", 2.0, &ok);
    TEST_ASSERT_MSG(ok && std::fabs(v2 - 20.0f) < 1e-5f, "value at t=2 == 20");
    float v3 = nanousd_samplef(prim, "x", 3.0, &ok);
    TEST_ASSERT_MSG(ok && std::fabs(v3 - 30.0f) < 1e-5f, "value at t=3 == 30");

    printf("  samplekey ordering OK: %.1f, %.1f, %.1f\n", k0, k1, k2);
    nanousd_close(stage);
}

