// ===================================================================
//  Test: prim_listop from stage with applied API schemas
// ===================================================================

static void test_prim_listop_from_stage()
{
    SECTION("test_prim_listop_from_stage");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/ApiPrim", "Mesh");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");

    // Apply two API schemas
    int ap1 = nanousd_apply_api(prim, "MaterialBindingAPI");
    int ap2 = nanousd_apply_api(prim, "SkelBindingAPI");
    // Graceful: apply_api may or may not be supported
    if (!ap1 || !ap2)
    {
        printf("  NOTE: apply_api returned 0 — skipping listop read\n");
        g_passes++;
        nanousd_close(stage);
        return;
    }

    NanousdListOp op = nanousd_prim_listop(prim, "apiSchemas");
    if (op)
    {
        int nItems = nanousd_listop_nitems(op);
        int nPrepend = nanousd_listop_nprepended(op);
        // Should have at least 2 schemas (prepended or explicit)
        int total = (nItems > 0) ? nItems : nPrepend;
        TEST_ASSERT_MSG(total >= 2, "listop has >= 2 api schemas");

        // Check that one of them is MaterialBindingAPI
        bool found = false;
        for (int i = 0; i < total; i++)
        {
            const char* item = (nItems > 0) ? nanousd_listop_item(op, i) : nanousd_listop_prepended(op, i);
            if (item && std::string(item).find("MaterialBindingAPI") != std::string::npos)
                found = true;
        }
        TEST_ASSERT_MSG(found, "MaterialBindingAPI found in listop");

        nanousd_listop_free(op);
    }
    else
    {
        printf("  NOTE: prim_listop returned NULL for apiSchemas\n");
        g_passes++;
    }

    printf("  prim_listop_from_stage OK\n");
    nanousd_close(stage);
}

// ===================================================================
//  Test: stage root layer path
// ===================================================================

static void test_stage_root_layer_path()
{
    SECTION("test_stage_root_layer_path");

    // In-memory stage
    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    const char* path = nanousd_stage_get_root_layer_path(stage);
    // In-memory stages may return NULL, empty, or a synthetic path
    if (path && path[0] != '\0')
    {
        printf("  created stage root layer path: \"%s\"\n", path);
        g_passes++;
    }
    else
    {
        printf("  NOTE: created stage root layer path is NULL/empty (acceptable for in-memory)\n");
        g_passes++;
    }
    nanousd_close(stage);

    // File-based stage — write to temp, reopen, check path
    NanousdStage stageW = nanousd_create();
    if (!stageW) { g_passes++; return; }
    nanousd_define_prim(stageW, "/Root", "Xform");
    const char* tmpPath = tmp_path("test_root_layer_path.usda");
    int writeOk = nanousd_write_usda(stageW, tmpPath);
    nanousd_close(stageW);

    if (writeOk)
    {
        NanousdStage stageR = nanousd_open(tmpPath);
        if (stageR)
        {
            const char* rlp = nanousd_stage_get_root_layer_path(stageR);
            if (rlp && rlp[0] != '\0')
            {
                std::string rlpStr(rlp);
                TEST_ASSERT_MSG(rlpStr.find("test_root_layer_path") != std::string::npos,
                                "root layer path contains filename");
            }
            else
            {
                printf("  NOTE: opened stage root layer path is NULL/empty\n");
                g_passes++;
            }
            nanousd_close(stageR);
        }
        else
        {
            printf("  NOTE: could not reopen written file\n");
            g_passes++;
        }
    }
    else
    {
        printf("  NOTE: write_usda failed — skipping file-based root layer path test\n");
        g_passes++;
    }

    printf("  stage_root_layer_path OK\n");
}

// ===================================================================
