// ===================================================================
//  test_bulk_relationship_targets — 100 rel targets, all readable
// ===================================================================

static void test_bulk_relationship_targets()
{
    SECTION("test_bulk_relationship_targets");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/RelBulk", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    nanousd_create_rel(prim, "manyTargets");

    const int N = 100;
    std::vector<std::string> paths(N);
    std::vector<const char*> ptrs(N);
    for (int i = 0; i < N; i++)
    {
        char buf[64];
        snprintf(buf, sizeof(buf), "/Target/Prim_%03d", i);
        paths[i] = buf;
        ptrs[i] = paths[i].c_str();
    }

    int ok = nanousd_set_reltargets(prim, "manyTargets", ptrs.data(), N);
    TEST_ASSERT_MSG(ok, "set 100 rel targets");

    int count = nanousd_nreltargets(prim, "manyTargets");
    TEST_ASSERT_MSG(count == N, "nreltargets == 100");

    // Verify all targets readable and correct
    int matchCount = 0;
    for (int i = 0; i < count; i++)
    {
        std::string target = safeStr(nanousd_reltarget(prim, "manyTargets", i));
        char expected[64];
        snprintf(expected, sizeof(expected), "/Target/Prim_%03d", i);
        if (target == expected) matchCount++;
    }
    TEST_ASSERT_MSG(matchCount == N, "all 100 rel targets match");

    printf("  bulk_relationship_targets OK: %d/%d matched\n", matchCount, N);
    nanousd_close(stage);
}

// ===================================================================
//  test_concurrent_stage_attributes — two stages, reads don't interfere
// ===================================================================

static void test_concurrent_stage_attributes()
{
    SECTION("test_concurrent_stage_attributes");

    NanousdStage stageA = nanousd_create();
    NanousdStage stageB = nanousd_create();
    TEST_ASSERT_MSG(stageA != nullptr, "create stageA");
    TEST_ASSERT_MSG(stageB != nullptr, "create stageB");
    if (!stageA || !stageB) { nanousd_close(stageA); nanousd_close(stageB); return; }

    NanousdPrim primA = nanousd_define_prim(stageA, "/Root/PrimA", "Scope");
    NanousdPrim primB = nanousd_define_prim(stageB, "/Root/PrimB", "Scope");
    TEST_ASSERT_MSG(primA != nullptr, "define primA");
    TEST_ASSERT_MSG(primB != nullptr, "define primB");

    nanousd_create_attrib(primA, "val", "float");
    nanousd_set_attribf(primA, "val", 111.0f);

    nanousd_create_attrib(primB, "val", "float");
    nanousd_set_attribf(primB, "val", 222.0f);

    nanousd_create_attrib(primA, "name", "string");
    nanousd_set_attribs(primA, "name", "stageA");

    nanousd_create_attrib(primB, "name", "string");
    nanousd_set_attribs(primB, "name", "stageB");

    // Read back — verify no cross-contamination
    int okA = 0, okB = 0;
    float fA = nanousd_attribf(primA, "val", &okA);
    float fB = nanousd_attribf(primB, "val", &okB);
    TEST_ASSERT_MSG(okA, "read primA float ok");
    TEST_ASSERT_MSG(okB, "read primB float ok");
    TEST_ASSERT_MSG(std::abs(fA - 111.0f) < 0.01f, "primA val == 111");
    TEST_ASSERT_MSG(std::abs(fB - 222.0f) < 0.01f, "primB val == 222");

    // String reads — copy before next call (shared buffer)
    int sOkA = 0;
    std::string sA = safeStr(nanousd_attribs(primA, "name", &sOkA));
    int sOkB = 0;
    std::string sB = safeStr(nanousd_attribs(primB, "name", &sOkB));
    TEST_ASSERT_MSG(sOkA, "read primA string ok");
    TEST_ASSERT_MSG(sOkB, "read primB string ok");
    TEST_ASSERT_MSG(sA == "stageA", "primA name == stageA");
    TEST_ASSERT_MSG(sB == "stageB", "primB name == stageB");

    printf("  concurrent_stage_attributes OK\n");
    nanousd_close(stageA);
    nanousd_close(stageB);
}

// ===================================================================
//  test_all_vector_integer_types — v2i, v3i, v4i with boundary values
// ===================================================================

static void test_all_vector_integer_types()
{
    SECTION("test_all_vector_integer_types");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/VecInt", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    // v2i with INT_MIN, INT_MAX
    {
        nanousd_create_attrib(prim, "v2iEdge", "int2");
        int v[2] = { INT_MIN, INT_MAX };
        nanousd_set_attribv2i(prim, "v2iEdge", v);
        int out[2] = {};
        int ok = nanousd_attribv2i(prim, "v2iEdge", out);
        TEST_ASSERT_MSG(ok, "read v2i edge");
        TEST_ASSERT_MSG(out[0] == INT_MIN, "v2i[0] == INT_MIN");
        TEST_ASSERT_MSG(out[1] == INT_MAX, "v2i[1] == INT_MAX");
    }

    // v2i with zeros
    {
        nanousd_create_attrib(prim, "v2iZero", "int2");
        int v[2] = { 0, 0 };
        nanousd_set_attribv2i(prim, "v2iZero", v);
        int out[2] = { -1, -1 };
        int ok = nanousd_attribv2i(prim, "v2iZero", out);
        TEST_ASSERT_MSG(ok, "read v2i zero");
        TEST_ASSERT_MSG(out[0] == 0 && out[1] == 0, "v2i zero values");
    }

    // v3i with boundary
    {
        nanousd_create_attrib(prim, "v3iEdge", "int3");
        int v[3] = { INT_MIN, 0, INT_MAX };
        nanousd_set_attribv3i(prim, "v3iEdge", v);
        int out[3] = {};
        int ok = nanousd_attribv3i(prim, "v3iEdge", out);
        TEST_ASSERT_MSG(ok, "read v3i edge");
        TEST_ASSERT_MSG(out[0] == INT_MIN, "v3i[0] == INT_MIN");
        TEST_ASSERT_MSG(out[1] == 0, "v3i[1] == 0");
        TEST_ASSERT_MSG(out[2] == INT_MAX, "v3i[2] == INT_MAX");
    }

    // v4i with boundary
    {
        nanousd_create_attrib(prim, "v4iEdge", "int4");
        int v[4] = { INT_MIN, -1, 0, INT_MAX };
        nanousd_set_attribv4i(prim, "v4iEdge", v);
        int out[4] = {};
        int ok = nanousd_attribv4i(prim, "v4iEdge", out);
        TEST_ASSERT_MSG(ok, "read v4i edge");
        TEST_ASSERT_MSG(out[0] == INT_MIN, "v4i[0] == INT_MIN");
        TEST_ASSERT_MSG(out[1] == -1, "v4i[1] == -1");
        TEST_ASSERT_MSG(out[2] == 0, "v4i[2] == 0");
        TEST_ASSERT_MSG(out[3] == INT_MAX, "v4i[3] == INT_MAX");
    }

    printf("  all_vector_integer_types OK\n");
    nanousd_close(stage);
}

// ===================================================================
//  test_float_precision_boundary — FLT_MIN, FLT_MAX, FLT_EPSILON roundtrip
// ===================================================================

static void test_float_precision_boundary()
{
    SECTION("test_float_precision_boundary");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/FloatPrec", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    struct FCase { const char* name; float val; };
    FCase cases[] = {
        {"fltMin",     FLT_MIN},
        {"fltMax",     FLT_MAX},
        {"fltEps",     FLT_EPSILON},
        {"negFltMax",  -FLT_MAX},
        {"one",        1.0f},
        {"negOne",     -1.0f},
        {"tiny",       1.0e-30f},
    };
    int nCases = sizeof(cases) / sizeof(cases[0]);

    for (int i = 0; i < nCases; i++)
    {
        nanousd_create_attrib(prim, cases[i].name, "float");
        nanousd_set_attribf(prim, cases[i].name, cases[i].val);

        int ok = 0;
        float got = nanousd_attribf(prim, cases[i].name, &ok);
        TEST_ASSERT_MSG(ok, "read float ok");

        if (cases[i].val == 0.0f)
        {
            TEST_ASSERT_MSG(got == 0.0f, "zero roundtrips");
        }
        else
        {
            float relErr = std::abs((got - cases[i].val) / cases[i].val);
            char msg[128];
            snprintf(msg, sizeof(msg), "float '%s' roundtrip relErr=%g", cases[i].name, relErr);
            TEST_ASSERT_MSG(relErr < 1e-6f, msg);
        }
    }

    printf("  float_precision_boundary OK: %d cases\n", nCases);
    nanousd_close(stage);
}

// ===================================================================
//  test_double_precision_boundary — DBL_MIN, DBL_MAX, DBL_EPSILON roundtrip
// ===================================================================

static void test_double_precision_boundary()
{
    SECTION("test_double_precision_boundary");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/DblPrec", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    struct DCase { const char* name; double val; };
    DCase cases[] = {
        {"dblMin",     DBL_MIN},
        {"dblMax",     DBL_MAX},
        {"dblEps",     DBL_EPSILON},
        {"negDblMax",  -DBL_MAX},
        {"one",        1.0},
        {"negOne",     -1.0},
        {"tiny",       1.0e-300},
    };
    int nCases = sizeof(cases) / sizeof(cases[0]);

    for (int i = 0; i < nCases; i++)
    {
        nanousd_create_attrib(prim, cases[i].name, "double");
        nanousd_set_attribd(prim, cases[i].name, cases[i].val);

        int ok = 0;
        double got = nanousd_attribd(prim, cases[i].name, &ok);
        TEST_ASSERT_MSG(ok, "read double ok");

        if (cases[i].val == 0.0)
        {
            TEST_ASSERT_MSG(got == 0.0, "zero roundtrips");
        }
        else
        {
            double relErr = std::abs((got - cases[i].val) / cases[i].val);
            char msg[128];
            snprintf(msg, sizeof(msg), "double '%s' roundtrip relErr=%g", cases[i].name, relErr);
            TEST_ASSERT_MSG(relErr < 1e-14, msg);
        }
    }

    printf("  double_precision_boundary OK: %d cases\n", nCases);
    nanousd_close(stage);
}

// ===================================================================
//  test_attrib_overwrite_sequence — overwrite 5 times, last value sticks
// ===================================================================

static void test_attrib_overwrite_sequence()
{
    SECTION("test_attrib_overwrite_sequence");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/Overwrite", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    // Float overwrite
    nanousd_create_attrib(prim, "fval", "float");
    float lastF = 0.0f;
    for (int i = 0; i < 5; i++)
    {
        lastF = (float)(i + 1) * 11.1f;
        nanousd_set_attribf(prim, "fval", lastF);
    }
    int ok = 0;
    float gotF = nanousd_attribf(prim, "fval", &ok);
    TEST_ASSERT_MSG(ok, "read overwritten float");
    TEST_ASSERT_MSG(std::abs(gotF - lastF) < 0.01f, "last float value sticks");

    // Int overwrite
    nanousd_create_attrib(prim, "ival", "int");
    int lastI = 0;
    for (int i = 0; i < 5; i++)
    {
        lastI = (i + 1) * 100;
        nanousd_set_attribi(prim, "ival", lastI);
    }
    ok = 0;
    int gotI = nanousd_attribi(prim, "ival", &ok);
    TEST_ASSERT_MSG(ok, "read overwritten int");
    TEST_ASSERT_MSG(gotI == lastI, "last int value sticks");

    // String overwrite
    nanousd_create_attrib(prim, "sval", "string");
    for (int i = 0; i < 5; i++)
    {
        char buf[32];
        snprintf(buf, sizeof(buf), "version_%d", i);
        nanousd_set_attribs(prim, "sval", buf);
    }
    ok = 0;
    std::string gotS = safeStr(nanousd_attribs(prim, "sval", &ok));
    TEST_ASSERT_MSG(ok, "read overwritten string");
    TEST_ASSERT_MSG(gotS == "version_4", "last string value sticks");

    // Double overwrite
    nanousd_create_attrib(prim, "dval", "double");
    double lastD = 0.0;
    for (int i = 0; i < 5; i++)
    {
        lastD = (double)(i + 1) * 99.99;
        nanousd_set_attribd(prim, "dval", lastD);
    }
    ok = 0;
    double gotD = nanousd_attribd(prim, "dval", &ok);
    TEST_ASSERT_MSG(ok, "read overwritten double");
    TEST_ASSERT_MSG(std::abs(gotD - lastD) < 0.001, "last double value sticks");

    // Bool overwrite
    nanousd_create_attrib(prim, "bval", "bool");
    for (int i = 0; i < 5; i++)
    {
        nanousd_set_attribb(prim, "bval", i % 2);
    }
    ok = 0;
    int gotB = nanousd_attribb(prim, "bval", &ok);
    TEST_ASSERT_MSG(ok, "read overwritten bool");
    TEST_ASSERT_MSG(gotB == 0, "last bool value sticks (4 % 2 == 0)");

    printf("  attrib_overwrite_sequence OK\n");
    nanousd_close(stage);
}

// ===================================================================
//  test_prim_traversal_order — index-based traversal visits all prims
// ===================================================================

static void test_prim_traversal_order()
{
    SECTION("test_prim_traversal_order");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    // Create prims in specific order
    const char* primPaths[] = {
        "/Alpha", "/Beta", "/Gamma", "/Delta", "/Epsilon",
        "/Alpha/Child1", "/Alpha/Child2", "/Beta/Sub1"
    };
    int nPaths = sizeof(primPaths) / sizeof(primPaths[0]);

    for (int i = 0; i < nPaths; i++)
    {
        NanousdPrim p = nanousd_define_prim(stage, primPaths[i], "Scope");
        TEST_ASSERT_MSG(p != nullptr, "define prim");
    }

    int np = nanousd_nprims(stage);
    TEST_ASSERT_MSG(np >= nPaths, "nprims >= created count");
    printf("  created %d prims, nprims reports %d\n", nPaths, np);

    // Traverse all via index and collect paths
    std::vector<std::string> visitedPaths;
    for (int i = 0; i < np; i++)
    {
        NanousdPrim p = nanousd_prim(stage, i);
        if (p)
        {
            std::string pp = safeStr(nanousd_path(p));
            if (!pp.empty()) visitedPaths.push_back(pp);
        }
    }

    // Verify all created prims are visited
    int found = 0;
    for (int i = 0; i < nPaths; i++)
    {
        for (size_t j = 0; j < visitedPaths.size(); j++)
        {
            if (visitedPaths[j] == primPaths[i])
            {
                found++;
                break;
            }
        }
    }
    TEST_ASSERT_MSG(found == nPaths, "all created prims visited via index traversal");

    printf("  prim_traversal_order OK: %d/%d found\n", found, nPaths);
    nanousd_close(stage);
}

// ===================================================================
//  test_nested_material_network_write — Material/Shader/Texture hierarchy
// ===================================================================

static void test_nested_material_network_write()
{
    SECTION("test_nested_material_network_write");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    // Create Material
    NanousdPrim mat = nanousd_define_prim(stage, "/World/Materials/MyMaterial", "Material");
    TEST_ASSERT_MSG(mat != nullptr, "define Material");

    // Create Shader under Material
    NanousdPrim shader = nanousd_define_prim(stage, "/World/Materials/MyMaterial/PBRShader", "Shader");
    TEST_ASSERT_MSG(shader != nullptr, "define Shader");

    nanousd_create_attrib(shader, "info:id", "token");
    nanousd_set_attrib_token(shader, "info:id", "UsdPreviewSurface");

    nanousd_create_attrib(shader, "inputs:diffuseColor", "color3f");
    float diffuse[3] = { 0.8f, 0.2f, 0.1f };
    nanousd_set_attribv3f(shader, "inputs:diffuseColor", diffuse);

    nanousd_create_attrib(shader, "inputs:metallic", "float");
    nanousd_set_attribf(shader, "inputs:metallic", 0.0f);

    nanousd_create_attrib(shader, "inputs:roughness", "float");
    nanousd_set_attribf(shader, "inputs:roughness", 0.5f);

    // Create Texture reader under Material
    NanousdPrim tex = nanousd_define_prim(stage, "/World/Materials/MyMaterial/DiffuseTexture", "Shader");
    TEST_ASSERT_MSG(tex != nullptr, "define Texture Shader");

    nanousd_create_attrib(tex, "info:id", "token");
    nanousd_set_attrib_token(tex, "info:id", "UsdUVTexture");

    nanousd_create_attrib(tex, "inputs:file", "asset");
    nanousd_set_attrib_asset(tex, "inputs:file", "textures/diffuse.png");

    // Serialize to USDA string
    const char* usda = nanousd_write_usda_string(stage);
    if (!usda)
    {
        g_passes++;
        printf("  nanousd_write_usda_string not supported — graceful skip\n");
        nanousd_close(stage);
        return;
    }

    std::string out(usda);
    nanousd_free_string(usda);

    // Verify hierarchy is present
    TEST_STR_HAS(out, "Material");
    TEST_STR_HAS(out, "PBRShader");
    TEST_STR_HAS(out, "DiffuseTexture");
    TEST_STR_HAS(out, "UsdPreviewSurface");
    TEST_STR_HAS(out, "UsdUVTexture");
    TEST_STR_HAS(out, "diffuse.png");

    printf("  nested_material_network_write OK (%zu bytes)\n", out.size());
    nanousd_close(stage);
}

// ===================================================================
//  test_hasattrib_comprehensive — verify hasattrib for various types
// ===================================================================

static void test_hasattrib_comprehensive()
{
    SECTION("test_hasattrib_comprehensive");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/HasAttr", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    // Create various attribute types
    const char* attrNames[] = {
        "myFloat", "myDouble", "myInt", "myBool", "myString",
        "myToken", "myV3f", "myV3d", "myM4d", "myIntArr"
    };
    const char* attrTypes[] = {
        "float", "double", "int", "bool", "string",
        "token", "float3", "double3", "matrix4d", "int[]"
    };
    int nAttrs = sizeof(attrNames) / sizeof(attrNames[0]);

    for (int i = 0; i < nAttrs; i++)
    {
        int cr = nanousd_create_attrib(prim, attrNames[i], attrTypes[i]);
        if (!cr)
        {
            g_passes++;
            printf("  create_attrib '%s' (%s) not supported — graceful\n",
                   attrNames[i], attrTypes[i]);
            continue;
        }

        int has = nanousd_hasattrib(prim, attrNames[i]);
        char msg[128];
        snprintf(msg, sizeof(msg), "hasattrib('%s') == 1 after create", attrNames[i]);
        TEST_ASSERT_MSG(has, msg);
    }

    // Verify non-existent attributes return 0
    TEST_ASSERT_MSG(!nanousd_hasattrib(prim, "nonExistent"), "hasattrib('nonExistent') == 0");
    TEST_ASSERT_MSG(!nanousd_hasattrib(prim, ""), "hasattrib('') == 0");
    TEST_ASSERT_MSG(!nanousd_hasattrib(prim, "my_Float"), "hasattrib('my_Float') == 0");

    printf("  hasattrib_comprehensive OK: %d types tested\n", nAttrs);
    nanousd_close(stage);
}

// ===================================================================
//  test_nattribs_count — create N attribs, verify count and enumeration
// ===================================================================

static void test_nattribs_count()
{
    SECTION("test_nattribs_count");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/CountAttribs", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    const int N = 20;
    std::vector<std::string> names(N);
    for (int i = 0; i < N; i++)
    {
        char buf[32];
        snprintf(buf, sizeof(buf), "attr_%02d", i);
        names[i] = buf;
        int cr = nanousd_create_attrib(prim, buf, "float");
        TEST_ASSERT_MSG(cr, "create_attrib ok");
        nanousd_set_attribf(prim, buf, (float)i);
    }

    int count = nanousd_nattribs(prim);
    TEST_ASSERT_MSG(count >= N, "nattribs >= N created");
    printf("  created %d attribs, nattribs reports %d\n", N, count);

    // Verify enumeration covers all created attributes
    std::vector<std::string> enumNames;
    for (int i = 0; i < count; i++)
    {
        std::string aname = safeStr(nanousd_attribname(prim, i));
        if (!aname.empty()) enumNames.push_back(aname);
    }

    int foundCount = 0;
    for (int i = 0; i < N; i++)
    {
        for (size_t j = 0; j < enumNames.size(); j++)
        {
            if (enumNames[j] == names[i])
            {
                foundCount++;
                break;
            }
        }
    }
    TEST_ASSERT_MSG(foundCount == N, "all created attribs found via enumeration");

    // Also verify values through enumeration
    for (int i = 0; i < N; i++)
    {
        int ok = 0;
        float val = nanousd_attribf(prim, names[i].c_str(), &ok);
        TEST_ASSERT_MSG(ok, "read enumerated attrib ok");
        TEST_ASSERT_MSG(std::abs(val - (float)i) < 0.01f, "enumerated attrib value correct");
    }

    printf("  nattribs_count OK: %d/%d found, values verified\n", foundCount, N);
    nanousd_close(stage);
}

// ===================================================================
//  test_empty_string_attribs — empty strings roundtrip correctly
// ===================================================================

static void test_empty_string_attribs()
{
    SECTION("test_empty_string_attribs");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "create stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/World/EmptyStr", "Scope");
    TEST_ASSERT_MSG(prim != nullptr, "define prim");

    // Write empty string
    nanousd_create_attrib(prim, "emptyStr", "string");
    int wOk = nanousd_set_attribs(prim, "emptyStr", "");
    TEST_ASSERT_MSG(wOk, "set empty string");

    int rOk = 0;
    std::string got = safeStr(nanousd_attribs(prim, "emptyStr", &rOk));
    TEST_ASSERT_MSG(rOk, "read empty string ok");
    TEST_ASSERT_MSG(got.empty(), "empty string roundtrips as empty");

    // Write empty token
    nanousd_create_attrib(prim, "emptyToken", "token");
    int tOk = nanousd_set_attrib_token(prim, "emptyToken", "");
    if (tOk)
    {
        int trOk = 0;
        std::string tGot = safeStr(nanousd_attrib_token(prim, "emptyToken", &trOk));
        if (trOk)
        {
            TEST_ASSERT_MSG(tGot.empty(), "empty token roundtrips as empty");
        }
        else
        {
            g_passes++;
            printf("  empty token read returned ok=0 (graceful)\n");
        }
    }
    else
    {
        g_passes++;
        printf("  set empty token returned 0 (graceful)\n");
    }

    // Write non-empty then overwrite with empty
    nanousd_create_attrib(prim, "wasNonEmpty", "string");
    nanousd_set_attribs(prim, "wasNonEmpty", "hello");
    nanousd_set_attribs(prim, "wasNonEmpty", "");
    rOk = 0;
    std::string got2 = safeStr(nanousd_attribs(prim, "wasNonEmpty", &rOk));
    TEST_ASSERT_MSG(rOk, "read overwritten-to-empty string ok");
    TEST_ASSERT_MSG(got2.empty(), "overwritten-to-empty string is empty");

    // Write/read through USDA serialization roundtrip
    const char* usda = nanousd_write_usda_string(stage);
    if (usda)
    {
        std::string out(usda);
        nanousd_free_string(usda);
        // Empty string should appear as ""
        TEST_STR_HAS(out, "\"\"");
        printf("  empty string appears in USDA output\n");
    }
    else
    {
        g_passes++;
        printf("  write_usda_string not supported — graceful skip\n");
    }

    printf("  empty_string_attribs OK\n");
    nanousd_close(stage);
}

// ===================================================================
//  Stress tests and edge cases (Phase 48)
// ===================================================================

static void test_1000_prims_stress()
{
    SECTION("test_1000_prims_stress");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "stage created");

    nanousd_define_prim(stage, "/Root", "Xform");

    // Create 1000 prims
    for (int i = 0; i < 1000; i++)
    {
        char path[128];
        snprintf(path, sizeof(path), "/Root/Prim%04d", i);
        NanousdPrim p = nanousd_define_prim(stage, path, "Mesh");
        TEST_ASSERT_MSG(p != nullptr, "prim created");
    }

    int np = nanousd_nprims(stage);
    TEST_ASSERT_MSG(np >= 1000, "1000+ prims in stage");

    // Verify all accessible via nanousd_prim() index
    int found_by_index = 0;
    for (int i = 0; i < nanousd_nprims(stage); i++)
    {
        NanousdPrim p = nanousd_prim(stage, i);
        if (p && nanousd_prim_isvalid(p))
            found_by_index++;
    }
    TEST_ASSERT_MSG(found_by_index >= 1000, "1000+ prims accessible by index");

    // Verify all accessible via nanousd_primpath() path lookup
    int found_by_path = 0;
    for (int i = 0; i < 1000; i++)
    {
        char path[128];
        snprintf(path, sizeof(path), "/Root/Prim%04d", i);
        NanousdPrim p = nanousd_primpath(stage, path);
        if (p && nanousd_prim_isvalid(p))
        {
            std::string gotPath = safeStr(nanousd_path(p));
            if (gotPath == path)
                found_by_path++;
        }
    }
    TEST_ASSERT_MSG(found_by_path == 1000, "all 1000 prims found by path");

    printf("  1000_prims_stress OK (index=%d, path=%d)\n", found_by_index, found_by_path);
    nanousd_close(stage);
}

