static void test_every_scalar_setter_getter()
{
    SECTION("test_every_scalar_setter_getter");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    NanousdPrim prim = nanousd_define_prim(stage, "/ScalarTest", "Xform");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");
    int ok = 0;

    // float
    nanousd_create_attrib(prim, "valFloat", "float");
    TEST_ASSERT_MSG(nanousd_set_attribf(prim, "valFloat", -1.5f), "set float");
    float rf = nanousd_attribf(prim, "valFloat", &ok);
    TEST_ASSERT_MSG(ok, "read float ok");
    TEST_ASSERT_MSG(std::fabs(rf - (-1.5f)) < 1e-6f, "float roundtrip");

    // double
    nanousd_create_attrib(prim, "valDouble", "double");
    TEST_ASSERT_MSG(nanousd_set_attribd(prim, "valDouble", 3.141592653589793), "set double");
    double rd = nanousd_attribd(prim, "valDouble", &ok);
    TEST_ASSERT_MSG(ok, "read double ok");
    TEST_ASSERT_MSG(std::fabs(rd - 3.141592653589793) < 1e-12, "double roundtrip");

    // int
    nanousd_create_attrib(prim, "valInt", "int");
    TEST_ASSERT_MSG(nanousd_set_attribi(prim, "valInt", -999), "set int");
    int ri = nanousd_attribi(prim, "valInt", &ok);
    TEST_ASSERT_MSG(ok, "read int ok");
    TEST_ASSERT_MSG(ri == -999, "int roundtrip");

    // int64
    nanousd_create_attrib(prim, "valInt64", "int64");
    TEST_ASSERT_MSG(nanousd_set_attribi64(prim, "valInt64", (int64_t)9876543210LL), "set int64");
    int64_t ri64 = nanousd_attribi64(prim, "valInt64", &ok);
    TEST_ASSERT_MSG(ok, "read int64 ok");
    TEST_ASSERT_MSG(ri64 == 9876543210LL, "int64 roundtrip");

    // bool
    nanousd_create_attrib(prim, "valBool", "bool");
    TEST_ASSERT_MSG(nanousd_set_attribb(prim, "valBool", 1), "set bool");
    int rb = nanousd_attribb(prim, "valBool", &ok);
    TEST_ASSERT_MSG(ok, "read bool ok");
    TEST_ASSERT_MSG(rb == 1, "bool roundtrip true");

    nanousd_set_attribb(prim, "valBool", 0);
    rb = nanousd_attribb(prim, "valBool", &ok);
    TEST_ASSERT_MSG(ok, "read bool false ok");
    TEST_ASSERT_MSG(rb == 0, "bool roundtrip false");

    // string
    nanousd_create_attrib(prim, "valStr", "string");
    TEST_ASSERT_MSG(nanousd_set_attribs(prim, "valStr", "hello world"), "set string");
    std::string rs = safeStr(nanousd_attribs(prim, "valStr", &ok));
    TEST_ASSERT_MSG(ok, "read string ok");
    TEST_ASSERT_MSG(rs == "hello world", "string roundtrip");

    nanousd_close(stage);
    printf("  test_every_scalar_setter_getter OK\n");
}

