static void test_attrib_namespace_enumeration()
{
    SECTION("test_attrib_namespace_enumeration");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    NanousdPrim prim = nanousd_define_prim(stage, "/NsTest", "Mesh");
    TEST_ASSERT_MSG(prim != nullptr, "defined prim");

    // Create attributes with namespaced names
    nanousd_create_attrib(prim, "primvars:st", "float2");
    nanousd_create_attrib(prim, "inputs:color", "color3f");
    nanousd_create_attrib(prim, "xformOp:translate", "double3");
    nanousd_create_attrib(prim, "plain", "float");

    // Set values so they are authored
    float st[] = {0.5f, 0.5f};
    nanousd_set_attribv2f(prim, "primvars:st", st);
    float col[] = {1.0f, 0.0f, 0.0f};
    nanousd_set_attribv3f(prim, "inputs:color", col);
    double xlate[] = {10.0, 20.0, 30.0};
    nanousd_set_attribv3d(prim, "xformOp:translate", xlate);
    nanousd_set_attribf(prim, "plain", 3.14f);

    // Enumerate all attributes
    int nattrs = nanousd_nattribs(prim);
    TEST_ASSERT_MSG(nattrs >= 4, "at least 4 attribs");

    bool foundPrimvars = false, foundInputs = false, foundXform = false, foundPlain = false;
    for (int i = 0; i < nattrs; i++)
    {
        std::string name = safeStr(nanousd_attribname(prim, i));
        if (name == "primvars:st") foundPrimvars = true;
        if (name == "inputs:color") foundInputs = true;
        if (name == "xformOp:translate") foundXform = true;
        if (name == "plain") foundPlain = true;
    }

    TEST_ASSERT_MSG(foundPrimvars, "found primvars:st in enumeration");
    TEST_ASSERT_MSG(foundInputs, "found inputs:color in enumeration");
    TEST_ASSERT_MSG(foundXform, "found xformOp:translate in enumeration");
    TEST_ASSERT_MSG(foundPlain, "found plain in enumeration");

    nanousd_close(stage);
    printf("  test_attrib_namespace_enumeration OK\n");
}

static void test_scene_complexity_benchmark()
{
    SECTION("test_scene_complexity_benchmark");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");

    // Create 200 prims with 5 attributes each (1000 attrs total)
    for (int p = 0; p < 200; p++)
    {
        char primPath[64];
        snprintf(primPath, sizeof(primPath), "/Scene/Prim%03d", p);
        NanousdPrim prim = nanousd_define_prim(stage, primPath, "Mesh");
        TEST_ASSERT_MSG(prim != nullptr, "define prim in benchmark");

        for (int a = 0; a < 5; a++)
        {
            char attrName[64];
            snprintf(attrName, sizeof(attrName), "attr%d", a);
            nanousd_create_attrib(prim, attrName, "float");
            nanousd_set_attribf(prim, attrName, (float)(p * 5 + a));
        }
    }

    // Serialize to USDA string
    const char* usda = nanousd_write_usda_string(stage);
    TEST_ASSERT_MSG(usda != nullptr, "serialize 200-prim scene");
    std::string out(usda);
    nanousd_free_string(usda);

    // Verify all prim paths appear in serialized output
    bool allFound = true;
    for (int p = 0; p < 200; p++)
    {
        char leafName[64];
        snprintf(leafName, sizeof(leafName), "Prim%03d", p);
        if (out.find(leafName) == std::string::npos)
        {
            allFound = false;
            char msg[128];
            snprintf(msg, sizeof(msg), "missing prim %s in USDA output", leafName);
            TEST_ASSERT_MSG(false, msg);
            break;
        }
    }
    if (allFound)
    {
        g_passes++;
    }

    // Verify the output is reasonably large (1000 attrs should produce significant text)
    TEST_ASSERT_MSG(out.size() > 5000, "USDA output is substantial");

    nanousd_close(stage);
    printf("  test_scene_complexity_benchmark OK\n");
}

