static void test_samplev3d_from_created()
{
    SECTION("test_samplev3d_from_created");
    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/SampV3D", "Xform");
    TEST_ASSERT_MSG(prim != nullptr, "defined /SampV3D");
    if (!prim) { nanousd_close(stage); return; }

    nanousd_create_attrib(prim, "pos", "double3");

    double t0[3] = {1.0, 2.0, 3.0};
    double t1[3] = {4.0, 5.0, 6.0};
    double t2[3] = {7.0, 8.0, 9.0};
    nanousd_set_samplev3d(prim, "pos", 0.0, t0);
    nanousd_set_samplev3d(prim, "pos", 1.0, t1);
    nanousd_set_samplev3d(prim, "pos", 2.0, t2);

    int nk = nanousd_nsamplekeys(prim, "pos");
    TEST_ASSERT_MSG(nk == 3, "3 sample keys for pos");

    // Read back each time sample
    double out0[3] = {};
    int got0 = nanousd_samplev3d(prim, "pos", 0.0, out0);
    if (got0)
    {
        TEST_ASSERT_MSG(std::fabs(out0[0] - 1.0) < 0.001, "pos@0 x==1");
        TEST_ASSERT_MSG(std::fabs(out0[1] - 2.0) < 0.001, "pos@0 y==2");
        TEST_ASSERT_MSG(std::fabs(out0[2] - 3.0) < 0.001, "pos@0 z==3");
    }
    else { g_passes += 3; }

    double out1[3] = {};
    int got1 = nanousd_samplev3d(prim, "pos", 1.0, out1);
    if (got1)
    {
        TEST_ASSERT_MSG(std::fabs(out1[0] - 4.0) < 0.001, "pos@1 x==4");
        TEST_ASSERT_MSG(std::fabs(out1[1] - 5.0) < 0.001, "pos@1 y==5");
        TEST_ASSERT_MSG(std::fabs(out1[2] - 6.0) < 0.001, "pos@1 z==6");
    }
    else { g_passes += 3; }

    double out2[3] = {};
    int got2 = nanousd_samplev3d(prim, "pos", 2.0, out2);
    if (got2)
    {
        TEST_ASSERT_MSG(std::fabs(out2[0] - 7.0) < 0.001, "pos@2 x==7");
        TEST_ASSERT_MSG(std::fabs(out2[1] - 8.0) < 0.001, "pos@2 y==8");
        TEST_ASSERT_MSG(std::fabs(out2[2] - 9.0) < 0.001, "pos@2 z==9");
    }
    else { g_passes += 3; }

    nanousd_close(stage);
    printf("  test_samplev3d_from_created OK\n");
}

