static void test_render_product_scene()
{
    SECTION("test_render_product_scene");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    nanousd_define_prim(stage, "/Render", "Scope");

    // Camera
    NanousdPrim cam = nanousd_define_prim(stage, "/Render/Camera", "Camera");
    TEST_ASSERT_MSG(cam != nullptr, "defined Camera");
    nanousd_create_attrib(cam, "focalLength", "float");
    nanousd_set_attribf(cam, "focalLength", 50.0f);

    // RenderProduct with camera binding and resolution
    NanousdPrim rp = nanousd_define_prim(stage, "/Render/Product", "RenderProduct");
    TEST_ASSERT_MSG(rp != nullptr, "defined RenderProduct");

    nanousd_create_rel(rp, "camera");
    const char* camTarget = "/Render/Camera";
    nanousd_set_reltargets(rp, "camera", &camTarget, 1);

    int res[] = {1920, 1080};
    nanousd_create_attrib(rp, "resolution", "int2");
    nanousd_set_attribv2i(rp, "resolution", res);

    nanousd_create_attrib(rp, "productName", "token");
    nanousd_set_attrib_token(rp, "productName", "beauty");

    // Serialize and verify
    std::string out = serializeStage(stage);
    TEST_STR_HAS(out, "def RenderProduct");
    TEST_STR_HAS(out, "def Camera");
    TEST_STR_HAS(out, "resolution");
    TEST_STR_HAS(out, "1920");
    TEST_STR_HAS(out, "1080");

    // Roundtrip via USDA string
    const char* usda = nanousd_write_usda_string(stage);
    if (usda)
    {
        const char* tmpFile = tmp_path("test_render_product.usda");
        FILE* fh = fopen(tmpFile, "w");
        if (fh) { fputs(usda, fh); fclose(fh); }
        nanousd_free_string(usda);

        NanousdStage reStage = nanousd_open(tmpFile);
        if (reStage)
        {
            NanousdPrim reRp = nanousd_primpath(reStage, "/Render/Product");
            if (reRp)
            {
                int reRes[2] = {};
                int got = nanousd_attribv2i(reRp, "resolution", reRes);
                TEST_ASSERT_MSG(got == 1 && reRes[0] == 1920 && reRes[1] == 1080,
                                "resolution roundtrip");
                int nTargets = nanousd_nreltargets(reRp, "camera");
                TEST_ASSERT_MSG(nTargets >= 1, "camera rel target roundtrip");
            }
            else { g_passes += 2; }
            nanousd_close(reStage);
        }
        else { g_passes += 2; }
        remove(tmpFile);
    }
    else { g_passes += 2; }

    nanousd_close(stage);
    printf("  test_render_product_scene OK\n");
}

static void test_instancer_with_positions_orientations()
{
    SECTION("test_instancer_with_positions_orientations");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim inst = nanousd_define_prim(stage, "/World/Instancer", "PointInstancer");
    TEST_ASSERT_MSG(inst != nullptr, "defined PointInstancer");

    // Positions (3 instances)
    float positions[] = {0,0,0, 1,0,0, 0,1,0};
    nanousd_create_attrib(inst, "positions", "point3f[]");
    nanousd_set_attribarrayv3f(inst, "positions", positions, 3);

    // Orientations (quatf[])
    float orientations[] = {1,0,0,0, 0.707f,0,0.707f,0, 0,0,1,0};
    nanousd_create_attrib(inst, "orientations", "quath[]");
    nanousd_set_attribarrayf(inst, "orientations", orientations, 12);

    // ProtoIndices
    int protoIndices[] = {0, 0, 1};
    nanousd_create_attrib(inst, "protoIndices", "int[]");
    nanousd_set_attribarrayi(inst, "protoIndices", protoIndices, 3);

    // Prototypes relationship
    nanousd_define_prim(stage, "/World/Instancer/Prototypes", "Scope");
    nanousd_define_prim(stage, "/World/Instancer/Prototypes/Cube", "Cube");
    nanousd_define_prim(stage, "/World/Instancer/Prototypes/Sphere", "Sphere");
    nanousd_create_rel(inst, "prototypes");
    const char* protoTargets[] = {
        "/World/Instancer/Prototypes/Cube",
        "/World/Instancer/Prototypes/Sphere"
    };
    nanousd_set_reltargets(inst, "prototypes", protoTargets, 2);

    // Roundtrip
    const char* tmpFile = tmp_path("test_instancer_pos_orient.usda");
    const char* usda = nanousd_write_usda_string(stage);
    if (usda)
    {
        FILE* fh = fopen(tmpFile, "w");
        if (fh) { fputs(usda, fh); fclose(fh); }
        nanousd_free_string(usda);

        NanousdStage reStage = nanousd_open(tmpFile);
        if (reStage)
        {
            NanousdPrim reInst = nanousd_primpath(reStage, "/World/Instancer");
            if (reInst)
            {
                int posLen = nanousd_attribarraylen(reInst, "positions");
                // positions is vec3f[], so length might be 3 (vec3 count) or 9 (flat)
                TEST_ASSERT_MSG(posLen > 0, "positions array has elements");

                int idxLen = nanousd_attribarraylen(reInst, "protoIndices");
                TEST_ASSERT_MSG(idxLen == 3, "protoIndices has 3 elements");

                int nProtoTargets = nanousd_nreltargets(reInst, "prototypes");
                TEST_ASSERT_MSG(nProtoTargets == 2, "prototypes rel has 2 targets");
            }
            else { g_passes += 3; }
            nanousd_close(reStage);
        }
        else { g_passes += 3; }
        remove(tmpFile);
    }
    else { g_passes += 3; }

    nanousd_close(stage);
    printf("  test_instancer_with_positions_orientations OK\n");
}

