static void test_points_prim_creation()
{
    SECTION("test_points_prim_creation");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    NanousdPrim pts = nanousd_define_prim(stage, "/World/Points", "Points");
    TEST_ASSERT_MSG(pts != nullptr, "defined Points");

    // Points
    float positions[] = {0,0,0, 1,2,3, -1,0.5f,2};
    nanousd_create_attrib(pts, "points", "point3f[]");
    nanousd_set_attribarrayv3f(pts, "points", positions, 3);

    // Widths
    float widths[] = {0.1f, 0.2f, 0.15f};
    nanousd_create_attrib(pts, "widths", "float[]");
    nanousd_set_attribarrayf(pts, "widths", widths, 3);

    // Ids
    int64_t ids[] = {100, 200, 300};
    nanousd_create_attrib(pts, "ids", "int64[]");
    // Use int array setter (ids stored as int64 but we write via available API)
    nanousd_set_attribarrayd(pts, "ids", (const double*)nullptr, 0); // clear
    // Actually set via int array
    int intIds[] = {100, 200, 300};
    nanousd_create_attrib(pts, "ids", "int[]");
    nanousd_set_attribarrayi(pts, "ids", intIds, 3);

    // Serialize
    std::string out = serializeStage(stage);
    TEST_STR_HAS(out, "def Points");
    TEST_STR_HAS(out, "points");
    TEST_STR_HAS(out, "widths");

    // Roundtrip
    const char* tmpFile = tmp_path("test_points_prim.usda");
    const char* usda = nanousd_write_usda_string(stage);
    if (usda)
    {
        FILE* fh = fopen(tmpFile, "w");
        if (fh) { fputs(usda, fh); fclose(fh); }
        nanousd_free_string(usda);

        NanousdStage reStage = nanousd_open(tmpFile);
        if (reStage)
        {
            NanousdPrim rePts = nanousd_primpath(reStage, "/World/Points");
            if (rePts)
            {
                std::string tn = safeStr(nanousd_typename(rePts));
                TEST_ASSERT_MSG(tn == "Points", "type is Points");

                int wLen = nanousd_attribarraylen(rePts, "widths");
                TEST_ASSERT_MSG(wLen == 3, "widths has 3 elements");
            }
            else { g_passes += 2; }
            nanousd_close(reStage);
        }
        else { g_passes += 2; }
        remove(tmpFile);
    }
    else { g_passes += 2; }

    nanousd_close(stage);
    printf("  test_points_prim_creation OK\n");
}

