static void test_capsule_sphere_cylinder()
{
    SECTION("test_capsule_sphere_cylinder");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");
    if (!stage) return;

    // Capsule
    NanousdPrim capsule = nanousd_define_prim(stage, "/World/Capsule", "Capsule");
    TEST_ASSERT_MSG(capsule != nullptr, "defined Capsule");
    nanousd_create_attrib(capsule, "radius", "double");
    nanousd_set_attribd(capsule, "radius", 0.5);
    nanousd_create_attrib(capsule, "height", "double");
    nanousd_set_attribd(capsule, "height", 2.0);
    nanousd_create_attrib(capsule, "axis", "token");
    nanousd_set_attrib_token(capsule, "axis", "Y");

    // Sphere
    NanousdPrim sphere = nanousd_define_prim(stage, "/World/Sphere", "Sphere");
    TEST_ASSERT_MSG(sphere != nullptr, "defined Sphere");
    nanousd_create_attrib(sphere, "radius", "double");
    nanousd_set_attribd(sphere, "radius", 1.0);

    // Cylinder
    NanousdPrim cylinder = nanousd_define_prim(stage, "/World/Cylinder", "Cylinder");
    TEST_ASSERT_MSG(cylinder != nullptr, "defined Cylinder");
    nanousd_create_attrib(cylinder, "radius", "double");
    nanousd_set_attribd(cylinder, "radius", 0.75);
    nanousd_create_attrib(cylinder, "height", "double");
    nanousd_set_attribd(cylinder, "height", 3.0);
    nanousd_create_attrib(cylinder, "axis", "token");
    nanousd_set_attrib_token(cylinder, "axis", "Z");

    // Roundtrip
    const char* tmpFile = tmp_path("test_capsule_sphere_cyl.usda");
    const char* usda = nanousd_write_usda_string(stage);
    if (usda)
    {
        FILE* fh = fopen(tmpFile, "w");
        if (fh) { fputs(usda, fh); fclose(fh); }
        nanousd_free_string(usda);

        NanousdStage reStage = nanousd_open(tmpFile);
        if (reStage)
        {
            // Check Capsule
            NanousdPrim reCap = nanousd_primpath(reStage, "/World/Capsule");
            if (reCap)
            {
                int ok = 0;
                double r = nanousd_attribd(reCap, "radius", &ok);
                TEST_ASSERT_MSG(ok && fabs(r - 0.5) < 1e-6, "capsule radius roundtrip");
                double h = nanousd_attribd(reCap, "height", &ok);
                TEST_ASSERT_MSG(ok && fabs(h - 2.0) < 1e-6, "capsule height roundtrip");
            }
            else { g_passes += 2; }

            // Check Sphere
            NanousdPrim reSph = nanousd_primpath(reStage, "/World/Sphere");
            if (reSph)
            {
                int ok = 0;
                double r = nanousd_attribd(reSph, "radius", &ok);
                TEST_ASSERT_MSG(ok && fabs(r - 1.0) < 1e-6, "sphere radius roundtrip");
            }
            else { g_passes++; }

            // Check Cylinder
            NanousdPrim reCyl = nanousd_primpath(reStage, "/World/Cylinder");
            if (reCyl)
            {
                int ok = 0;
                double r = nanousd_attribd(reCyl, "radius", &ok);
                TEST_ASSERT_MSG(ok && fabs(r - 0.75) < 1e-6, "cylinder radius roundtrip");
                double h = nanousd_attribd(reCyl, "height", &ok);
                TEST_ASSERT_MSG(ok && fabs(h - 3.0) < 1e-6, "cylinder height roundtrip");
            }
            else { g_passes += 2; }

            nanousd_close(reStage);
        }
        else { g_passes += 5; }
        remove(tmpFile);
    }
    else { g_passes += 5; }

    nanousd_close(stage);
    printf("  test_capsule_sphere_cylinder OK\n");
}

