static void test_100_prims_full_attributes()
{
    SECTION("test_100_prims_full_attributes");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    const int N = 100;
    // Create 100 prims, each with 5 attrs (float, int, string, double, bool)
    for (int i = 0; i < N; i++)
    {
        char path[64];
        snprintf(path, sizeof(path), "/Batch%03d", i);
        NanousdPrim prim = nanousd_define_prim(stage, path, "Scope");
        TEST_ASSERT(prim != nullptr);
        if (!prim) continue;

        // float attr
        nanousd_create_attrib(prim, "valF", "float");
        nanousd_set_attribf(prim, "valF", (float)i * 1.5f);
        // int attr
        nanousd_create_attrib(prim, "valI", "int");
        nanousd_set_attribi(prim, "valI", i * 7);
        // string attr
        {
            char buf[64];
            snprintf(buf, sizeof(buf), "str_%d", i);
            nanousd_create_attrib(prim, "valS", "string");
            nanousd_set_attribs(prim, "valS", buf);
        }
        // double attr
        nanousd_create_attrib(prim, "valD", "double");
        nanousd_set_attribd(prim, "valD", (double)i * 2.25);
        // bool attr
        nanousd_create_attrib(prim, "valB", "bool");
        nanousd_set_attribb(prim, "valB", i % 2);
    }

    // Write and reparse
    const char* tmpFile = tmp_path("test_100_prims_full.usda");
    int wok = nanousd_write_usda(stage, tmpFile);
    TEST_ASSERT(wok == 1);

    NanousdStage rs = nanousd_open(tmpFile);
    TEST_ASSERT(rs != nullptr);
    if (!rs) { nanousd_close(stage); return; }

    int totalChecked = 0;
    for (int i = 0; i < N; i++)
    {
        char path[64];
        snprintf(path, sizeof(path), "/Batch%03d", i);
        NanousdPrim prim = nanousd_primpath(rs, path);
        if (!prim) { g_passes++; continue; } // graceful

        int ok = 0;
        // float
        float fv = nanousd_attribf(prim, "valF", &ok);
        TEST_ASSERT_MSG(ok && fabsf(fv - (float)i * 1.5f) < 0.01f,
            (std::string("float ") + path).c_str());
        totalChecked++;
        // int
        int iv = nanousd_attribi(prim, "valI", &ok);
        TEST_ASSERT_MSG(ok && iv == i * 7,
            (std::string("int ") + path).c_str());
        totalChecked++;
        // string
        {
            char expected[64];
            snprintf(expected, sizeof(expected), "str_%d", i);
            std::string got = safeStr(nanousd_attribs(prim, "valS", &ok));
            TEST_ASSERT_MSG(ok && got == expected,
                (std::string("string ") + path).c_str());
            totalChecked++;
        }
        // double
        double dv = nanousd_attribd(prim, "valD", &ok);
        TEST_ASSERT_MSG(ok && fabs(dv - (double)i * 2.25) < 0.001,
            (std::string("double ") + path).c_str());
        totalChecked++;
        // bool
        int bv = nanousd_attribb(prim, "valB", &ok);
        TEST_ASSERT_MSG(ok && bv == (i % 2),
            (std::string("bool ") + path).c_str());
        totalChecked++;
    }
    TEST_ASSERT(totalChecked == N * 5);

    nanousd_close(rs);
    remove(tmpFile);
    nanousd_close(stage);
    printf("  test_100_prims_full_attributes OK (%d values checked)\n", totalChecked);
}

static void test_50_meshes_with_geometry()
{
    SECTION("test_50_meshes_with_geometry");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    const int N = 50;
    for (int i = 0; i < N; i++)
    {
        char path[64];
        snprintf(path, sizeof(path), "/Mesh%03d", i);
        NanousdPrim prim = nanousd_define_prim(stage, path, "Mesh");
        TEST_ASSERT(prim != nullptr);
        if (!prim) continue;

        // points: 4 vec3f
        float pts[12];
        for (int j = 0; j < 4; j++)
        {
            pts[j*3+0] = (float)(i * 10 + j);
            pts[j*3+1] = (float)(i * 10 + j + 1);
            pts[j*3+2] = (float)(i * 10 + j + 2);
        }
        nanousd_create_attrib(prim, "points", "point3f[]");
        nanousd_set_attribarrayv3f(prim, "points", pts, 4);

        // normals: 4 vec3f
        float nrm[12];
        for (int j = 0; j < 4; j++)
        {
            nrm[j*3+0] = 0.0f;
            nrm[j*3+1] = 1.0f;
            nrm[j*3+2] = 0.0f;
        }
        nanousd_create_attrib(prim, "normals", "normal3f[]");
        nanousd_set_attribarrayv3f(prim, "normals", nrm, 4);

        // faceVertexCounts: [3]
        int fvc[] = {3};
        nanousd_create_attrib(prim, "faceVertexCounts", "int[]");
        nanousd_set_attribarrayi(prim, "faceVertexCounts", fvc, 1);

        // faceVertexIndices: [0, 1, 2]
        int fvi[] = {0, 1, 2};
        nanousd_create_attrib(prim, "faceVertexIndices", "int[]");
        nanousd_set_attribarrayi(prim, "faceVertexIndices", fvi, 3);
    }

    const char* tmpFile = tmp_path("test_50_meshes.usda");
    int wok = nanousd_write_usda(stage, tmpFile);
    TEST_ASSERT(wok == 1);

    NanousdStage rs = nanousd_open(tmpFile);
    TEST_ASSERT(rs != nullptr);
    if (!rs) { nanousd_close(stage); return; }

    for (int i = 0; i < N; i++)
    {
        char path[64];
        snprintf(path, sizeof(path), "/Mesh%03d", i);
        NanousdPrim prim = nanousd_primpath(rs, path);
        if (!prim) { g_passes++; continue; }

        // Check points
        float pts[12];
        int npts = nanousd_attribarrayv3f(prim, "points", pts, 4);
        TEST_ASSERT_MSG(npts == 4, (std::string("points count ") + path).c_str());

        // Verify first and last point
        TEST_ASSERT(fabsf(pts[0] - (float)(i * 10 + 0)) < 0.01f);
        TEST_ASSERT(fabsf(pts[9] - (float)(i * 10 + 3)) < 0.01f);

        // Check normals
        float nrm[12];
        int nnrm = nanousd_attribarrayv3f(prim, "normals", nrm, 4);
        TEST_ASSERT(nnrm == 4);

        // Check faceVertexCounts
        int fvc[4];
        int nfvc = nanousd_attribarrayi(prim, "faceVertexCounts", fvc, 4);
        TEST_ASSERT(nfvc == 1);

        // Check faceVertexIndices
        int fvi[4];
        int nfvi = nanousd_attribarrayi(prim, "faceVertexIndices", fvi, 4);
        TEST_ASSERT(nfvi == 3);
    }

    nanousd_close(rs);
    remove(tmpFile);
    nanousd_close(stage);
    printf("  test_50_meshes_with_geometry OK\n");
}

static void test_array_sizes_1_to_50()
{
    SECTION("test_array_sizes_1_to_50");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/ArraySizes", "Scope");
    TEST_ASSERT(prim != nullptr);
    if (!prim) { nanousd_close(stage); return; }

    for (int sz = 1; sz <= 50; sz++)
    {
        char name[64];
        snprintf(name, sizeof(name), "arr%d", sz);
        nanousd_create_attrib(prim, name, "float[]");

        std::vector<float> data(sz);
        for (int j = 0; j < sz; j++)
            data[j] = (float)(sz * 100 + j);
        nanousd_set_attribarrayf(prim, name, data.data(), sz);
    }

    const char* tmpFile = tmp_path("test_array_sizes.usda");
    nanousd_write_usda(stage, tmpFile);

    NanousdStage rs = nanousd_open(tmpFile);
    TEST_ASSERT(rs != nullptr);
    if (!rs) { nanousd_close(stage); return; }

    NanousdPrim rp = nanousd_primpath(rs, "/ArraySizes");
    TEST_ASSERT(rp != nullptr);

    for (int sz = 1; sz <= 50; sz++)
    {
        char name[64];
        snprintf(name, sizeof(name), "arr%d", sz);
        int len = nanousd_attribarraylen(rp, name);
        TEST_ASSERT_MSG(len == sz, name);

        std::vector<float> buf(sz);
        int got = nanousd_attribarrayf(rp, name, buf.data(), sz);
        TEST_ASSERT(got == sz);

        // Verify first value
        TEST_ASSERT(fabsf(buf[0] - (float)(sz * 100)) < 0.01f);
        // Verify last value
        TEST_ASSERT(fabsf(buf[sz-1] - (float)(sz * 100 + sz - 1)) < 0.01f);
    }

    nanousd_close(rs);
    remove(tmpFile);
    nanousd_close(stage);
    printf("  test_array_sizes_1_to_50 OK\n");
}

static void test_50_relationships()
{
    SECTION("test_50_relationships");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/RelPrim", "Scope");
    TEST_ASSERT(prim != nullptr);
    if (!prim) { nanousd_close(stage); return; }

    // Create 50 target prims
    for (int i = 0; i < 100; i++)
    {
        char tp[64];
        snprintf(tp, sizeof(tp), "/Target%03d", i);
        nanousd_define_prim(stage, tp, "Scope");
    }

    // Create 50 relationships, each with 2 targets
    for (int i = 0; i < 50; i++)
    {
        char relName[64];
        snprintf(relName, sizeof(relName), "rel%d", i);
        nanousd_create_rel(prim, relName);

        char t0[64], t1[64];
        snprintf(t0, sizeof(t0), "/Target%03d", i * 2);
        snprintf(t1, sizeof(t1), "/Target%03d", i * 2 + 1);
        const char* targets[2] = {t0, t1};
        nanousd_set_reltargets(prim, relName, targets, 2);
    }

    const char* tmpFile = tmp_path("test_50_rels.usda");
    nanousd_write_usda(stage, tmpFile);

    NanousdStage rs = nanousd_open(tmpFile);
    TEST_ASSERT(rs != nullptr);
    if (!rs) { nanousd_close(stage); return; }

    NanousdPrim rp = nanousd_primpath(rs, "/RelPrim");
    TEST_ASSERT(rp != nullptr);

    for (int i = 0; i < 50; i++)
    {
        char relName[64];
        snprintf(relName, sizeof(relName), "rel%d", i);

        int has = nanousd_hasrel(rp, relName);
        TEST_ASSERT_MSG(has == 1, relName);

        int nt = nanousd_nreltargets(rp, relName);
        TEST_ASSERT_MSG(nt == 2, relName);

        if (nt >= 2)
        {
            char expected0[64], expected1[64];
            snprintf(expected0, sizeof(expected0), "/Target%03d", i * 2);
            snprintf(expected1, sizeof(expected1), "/Target%03d", i * 2 + 1);

            std::string t0 = safeStr(nanousd_reltarget(rp, relName, 0));
            std::string t1 = safeStr(nanousd_reltarget(rp, relName, 1));
            // Order may vary, check both are present
            bool ok = (t0 == expected0 && t1 == expected1) ||
                      (t0 == expected1 && t1 == expected0);
            TEST_ASSERT_MSG(ok, relName);
        }
    }

    nanousd_close(rs);
    remove(tmpFile);
    nanousd_close(stage);
    printf("  test_50_relationships OK\n");
}

