    if (!stage) return;

    NanousdPrim prim = nanousd_define_prim(stage, "/V3fArrays", "Scope");
    TEST_ASSERT(prim != nullptr);
    if (!prim) { nanousd_close(stage); return; }

    int sizes[] = {1, 5, 10, 50, 100};
    const int NSIZES = 5;

    for (int s = 0; s < NSIZES; s++)
    {
        int sz = sizes[s];
        char name[64];
        snprintf(name, sizeof(name), "v3f_%d", sz);
        nanousd_create_attrib(prim, name, "float3[]");

        std::vector<float> data(sz * 3);
        for (int j = 0; j < sz * 3; j++)
            data[j] = (float)(s * 10000 + j);
        nanousd_set_attribarrayv3f(prim, name, data.data(), sz);
    }

    const char* tmpFile = tmp_path("test_v3f_sizes.usda");
    nanousd_write_usda(stage, tmpFile);

    NanousdStage rs = nanousd_open(tmpFile);
    TEST_ASSERT(rs != nullptr);
    if (!rs) { nanousd_close(stage); return; }

    NanousdPrim rp = nanousd_primpath(rs, "/V3fArrays");
    TEST_ASSERT(rp != nullptr);

    for (int s = 0; s < NSIZES; s++)
    {
        int sz = sizes[s];
        char name[64];
        snprintf(name, sizeof(name), "v3f_%d", sz);

        int len = nanousd_attribarraylen(rp, name);
        TEST_ASSERT_MSG(len == sz, name);

        std::vector<float> buf(sz * 3);
        int got = nanousd_attribarrayv3f(rp, name, buf.data(), sz);
        TEST_ASSERT_MSG(got == sz, name);

        // Verify first element
        TEST_ASSERT(fabsf(buf[0] - (float)(s * 10000)) < 0.1f);
        // Verify last element's z
        TEST_ASSERT(fabsf(buf[sz*3-1] - (float)(s * 10000 + sz*3-1)) < 0.1f);
    }

    nanousd_close(rs);
    remove(tmpFile);
    nanousd_close(stage);
    printf("  test_v3f_array_sizes_varied OK\n");
