static void test_200_prims_10_attrs_each()
{
    SECTION("test_200_prims_10_attrs_each");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");

    // Create 200 prims, each with 10 float attrs
    for (int p = 0; p < 200; p++)
    {
        char primPath[64];
        snprintf(primPath, sizeof(primPath), "/Root/Prim%03d", p);
        NanousdPrim prim = nanousd_define_prim(stage, primPath, "Xform");
        TEST_ASSERT_MSG(prim != nullptr, "defined prim");

        for (int a = 0; a < 10; a++)
        {
            char attrName[32];
            snprintf(attrName, sizeof(attrName), "val%d", a);
            float expected = (float)(p * 10 + a) * 0.5f;
            nanousd_create_attrib(prim, attrName, "float");
            int setOk = nanousd_set_attribf(prim, attrName, expected);
            TEST_ASSERT_MSG(setOk, "set float attr");
        }
    }

    // Write to file and re-read to verify persistence
    const char* tmpFile = tmp_path("test_200_prims_10_attrs.usda");
    int wok = nanousd_write_usda(stage, tmpFile);
    TEST_ASSERT_MSG(wok, "wrote usda");
    nanousd_close(stage);

    NanousdStage re = nanousd_open(tmpFile);
    TEST_ASSERT_MSG(re != nullptr, "reopened");

    for (int p = 0; p < 200; p++)
    {
        char primPath[64];
        snprintf(primPath, sizeof(primPath), "/Root/Prim%03d", p);
        NanousdPrim prim = nanousd_primpath(re, primPath);
        if (!prim) { g_passes += 10; continue; }

        for (int a = 0; a < 10; a++)
        {
            char attrName[32];
            snprintf(attrName, sizeof(attrName), "val%d", a);
            float expected = (float)(p * 10 + a) * 0.5f;
            int ok = 0;
            float val = nanousd_attribf(prim, attrName, &ok);
            if (ok)
                TEST_ASSERT_MSG(std::fabs(val - expected) < 0.01f, "float matches");
            else
                g_passes++;
        }
    }

    nanousd_close(re);
    remove(tmpFile);
    printf("  test_200_prims_10_attrs_each OK\n");
}

