static void test_50_listop_operations()
{
    SECTION("test_50_listop_operations");

    for (int i = 0; i < 50; i++)
    {
        int nPrepend = (i % 4) + 1;  // 1-4 prepend items
        int nAppend  = (i % 3) + 1;  // 1-3 append items

        std::vector<std::string> prependStrs(nPrepend);
        std::vector<std::string> appendStrs(nAppend);
        std::vector<const char*> prependPtrs(nPrepend);
        std::vector<const char*> appendPtrs(nAppend);

        for (int j = 0; j < nPrepend; j++)
        {
            char buf[32];
            snprintf(buf, sizeof(buf), "Prep%d_%d", i, j);
            prependStrs[j] = buf;
            prependPtrs[j] = prependStrs[j].c_str();
        }
        for (int j = 0; j < nAppend; j++)
        {
            char buf[32];
            snprintf(buf, sizeof(buf), "App%d_%d", i, j);
            appendStrs[j] = buf;
            appendPtrs[j] = appendStrs[j].c_str();
        }

        NanousdListOp op = nanousd_listop_create(
            prependPtrs.data(), nPrepend,
            appendPtrs.data(), nAppend,
            nullptr, 0);
        TEST_ASSERT_MSG(op != nullptr, "created listop");
        TEST_ASSERT_MSG(nanousd_listop_nprepended(op) == nPrepend, "prepend count");
        TEST_ASSERT_MSG(nanousd_listop_nappended(op) == nAppend, "append count");

        nanousd_listop_free(op);
    }

    printf("  test_50_listop_operations OK\n");
}

static void test_200_child_prims_enumeration()
{
    SECTION("test_200_child_prims_enumeration");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT_MSG(stage != nullptr, "created stage");

    NanousdPrim parent = nanousd_define_prim(stage, "/Parent", "Xform");
    TEST_ASSERT_MSG(parent != nullptr, "defined parent");

    // Create 200 children
    std::vector<std::string> expectedNames(200);
    for (int i = 0; i < 200; i++)
    {
        char childPath[64], childName[32];
        snprintf(childName, sizeof(childName), "Child%03d", i);
        snprintf(childPath, sizeof(childPath), "/Parent/%s", childName);
        expectedNames[i] = childName;
        NanousdPrim ch = nanousd_define_prim(stage, childPath, "Scope");
        TEST_ASSERT_MSG(ch != nullptr, "defined child");
    }

    // Re-acquire parent after all defines
    parent = nanousd_primpath(stage, "/Parent");
    TEST_ASSERT_MSG(parent != nullptr, "re-acquired parent");

    int nch = nanousd_nchildren(parent);
    TEST_ASSERT_MSG(nch == 200, "200 children");

    for (int i = 0; i < nch && i < 200; i++)
    {
        NanousdPrim ch = nanousd_child(parent, i);
        TEST_ASSERT_MSG(ch != nullptr, "child exists");

        std::string name = safeStr(nanousd_name(ch));
        TEST_ASSERT_MSG(name == expectedNames[i], "child name matches");

        char expectedPath[64];
        snprintf(expectedPath, sizeof(expectedPath), "/Parent/%s", expectedNames[i].c_str());
        std::string path = safeStr(nanousd_path(ch));
        TEST_ASSERT_MSG(path == expectedPath, "child path matches");
    }

    nanousd_close(stage);
    printf("  test_200_child_prims_enumeration OK\n");
}

