static void test_500_prims_5_attrs()
{
    SECTION("test_500_prims_5_attrs");

    const char* outFile = tmp_path("test_500p5a.usda");
    remove(outFile);

    // --- Write phase ---
    {
        NanousdStage stage = nanousd_create();
        TEST_ASSERT_MSG(stage != nullptr, "500p5a: create stage");
        if (!stage) return;

        for (int i = 0; i < 500; i++)
        {
            char path[64];
            snprintf(path, sizeof(path), "/Root/P%04d", i);
            NanousdPrim p = nanousd_define_prim(stage, path, "Xform");
            TEST_ASSERT_MSG(p != nullptr, "500p5a: define prim");
            if (!p) continue;
            for (int a = 0; a < 5; a++)
            {
                char aname[32];
                snprintf(aname, sizeof(aname), "val%d", a);
                nanousd_create_attrib(p, aname, "float");
                float v = (float)(i * 5 + a) * 0.1f;
                nanousd_set_attribf(p, aname, v);
            }
        }

        int ok = nanousd_write_usda(stage, outFile);
        TEST_ASSERT_MSG(ok == 1, "500p5a: write usda");
        nanousd_close(stage);
    }

    // --- Read-back phase ---
    {
        NanousdStage stage = nanousd_open(outFile);
        TEST_ASSERT_MSG(stage != nullptr, "500p5a: reopen");
        if (!stage) return;

        for (int i = 0; i < 500; i++)
        {
            char path[64];
            snprintf(path, sizeof(path), "/Root/P%04d", i);
            NanousdPrim p = nanousd_primpath(stage, path);
            TEST_ASSERT_MSG(p != nullptr, "500p5a: find prim");
            if (!p) continue;
            for (int a = 0; a < 5; a++)
            {
                char aname[32];
                snprintf(aname, sizeof(aname), "val%d", a);
                int rok = 0;
                float v = nanousd_attribf(p, aname, &rok);
                float expected = (float)(i * 5 + a) * 0.1f;
                if (rok)
                    TEST_ASSERT_MSG(std::fabs(v - expected) < 0.02f, "500p5a: value match");
                else
                    g_passes++; // graceful
            }
        }

        nanousd_close(stage);
    }

    remove(outFile);
    printf("  test_500_prims_5_attrs OK\n");
}

