    {
        char aname[32];
        snprintf(aname, sizeof(aname), "arr%03d", i);
        nanousd_create_attrib(p, aname, "float[]");
        int sz = i + 1; // sizes 1..100
        std::vector<float> data(sz);
        for (int j = 0; j < sz; j++)
            data[j] = (float)(i * 100 + j);
        nanousd_set_attribarrayf(p, aname, data.data(), sz);
    }

    const char* f = tmp_path("test_100fa.usda");
    remove(f);
    nanousd_write_usda(stage, f);
    nanousd_close(stage);

