static void test_5000_prims_typename_verify()
{
    SECTION("test_5000_prims_typename_verify");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    const char* types[5] = { "Mesh", "Xform", "Scope", "Camera", "Material" };
    for (int t = 0; t < 5; t++)
    {
        for (int i = 0; i < 1000; i++)
        {
            char path[64];
            snprintf(path, 64, "/T%d/P%d", t, i);
            NanousdPrim p = nanousd_define_prim(stage, path, types[t]);
            TEST_ASSERT(p != nullptr);
        }
    }

    const char* f = tmp_path("test_5000ptv.usda");
    remove(f);
    int wok = nanousd_write_usda(stage, f);
    TEST_ASSERT(wok == 1);
    nanousd_close(stage);

    stage = nanousd_open(f);
    TEST_ASSERT(stage != nullptr);
    if (!stage) { remove(f); return; }

    for (int t = 0; t < 5; t++)
    {
        for (int i = 0; i < 1000; i++)
        {
            char path[64];
            snprintf(path, 64, "/T%d/P%d", t, i);
            NanousdPrim p = nanousd_primpath(stage, path);
            if (!p) { TEST_ASSERT_MSG(false, path); continue; }
            std::string tn = safeStr(nanousd_typename(p));
            TEST_ASSERT_MSG(tn == types[t], path);
        }
    }

    nanousd_close(stage);
    remove(f);
    printf("  test_5000_prims_typename_verify OK\n");
}

static void test_3000_float_attrs_value_check()
{
    SECTION("test_3000_float_attrs_value_check");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    // 30 prims x 100 float attrs = 3000 attrs
    for (int p = 0; p < 30; p++)
    {
        char primPath[64];
        snprintf(primPath, 64, "/Root/F%02d", p);
        NanousdPrim prim = nanousd_define_prim(stage, primPath, "Xform");
        TEST_ASSERT(prim != nullptr);
        if (!prim) continue;

        for (int a = 0; a < 100; a++)
        {
            char attr[32];
            snprintf(attr, 32, "fv%03d", a);
            int cr = nanousd_create_attrib(prim, attr, "float");
            TEST_ASSERT(cr == 1);
            float val = (float)(p * 100 + a) * 0.001f;
            int sr = nanousd_set_attribf(prim, attr, val);
            TEST_ASSERT(sr == 1);
        }
    }

    const char* f = tmp_path("test_3000fav.usda");
    remove(f);
    int wok = nanousd_write_usda(stage, f);
    TEST_ASSERT(wok == 1);
    nanousd_close(stage);

    stage = nanousd_open(f);
    TEST_ASSERT(stage != nullptr);
    if (!stage) { remove(f); return; }

    for (int p = 0; p < 30; p++)
    {
        char primPath[64];
        snprintf(primPath, 64, "/Root/F%02d", p);
        NanousdPrim prim = nanousd_primpath(stage, primPath);
        if (!prim) { TEST_ASSERT_MSG(false, primPath); continue; }

        for (int a = 0; a < 100; a++)
        {
            char attr[32];
            snprintf(attr, 32, "fv%03d", a);
            int ok = 0;
            float val = nanousd_attribf(prim, attr, &ok);
            TEST_ASSERT(ok == 1);
            float expected = (float)(p * 100 + a) * 0.001f;
            TEST_ASSERT(fabsf(val - expected) < 1e-4f);
        }
    }

    nanousd_close(stage);
    remove(f);
    printf("  test_3000_float_attrs_value_check OK\n");
}

