static void test_2000_hasattrib_nattribs()
{
    SECTION("test_2000_hasattrib_nattribs");

    NanousdStage stage = nanousd_create();
    TEST_ASSERT(stage != nullptr);
    if (!stage) return;

    // 2 prims x 1000 attrs each
    for (int p = 0; p < 2; p++)
    {
        char primPath[64];
        snprintf(primPath, 64, "/Root/H%d", p);
        NanousdPrim prim = nanousd_define_prim(stage, primPath, "Xform");
        TEST_ASSERT(prim != nullptr);
        if (!prim) continue;

        for (int a = 0; a < 1000; a++)
        {
            char attr[32];
            snprintf(attr, 32, "a%04d", a);
            nanousd_create_attrib(prim, attr, "float");
            nanousd_set_attribf(prim, attr, (float)a);
        }
    }

    // Verify hasattrib for all 2000 attrs + nattribs on each prim
    for (int p = 0; p < 2; p++)
    {
        char primPath[64];
        snprintf(primPath, 64, "/Root/H%d", p);
        NanousdPrim prim = nanousd_primpath(stage, primPath);
        TEST_ASSERT(prim != nullptr);
        if (!prim) continue;

        int na = nanousd_nattribs(prim);
        TEST_ASSERT(na >= 1000);

        for (int a = 0; a < 1000; a++)
        {
            char attr[32];
            snprintf(attr, 32, "a%04d", a);
            int has = nanousd_hasattrib(prim, attr);
            TEST_ASSERT(has == 1);
        }
    }

    nanousd_close(stage);
    printf("  test_2000_hasattrib_nattribs OK\n");
}

